{
  "name": "HTML/CSS Generator",
  "description": "A simple block-based HTML and CSS generator allowing users to format headings and text blocks without writing code."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type BlockType = 'heading' | 'paragraph';

export interface StyleConfig {
  color: string;
  fontSize: string;
  backgroundColor?: string;
  padding?: string;
  borderRadius?: string;
  fontWeight?: string;
  textAlign?: 'left' | 'center' | 'right';
}

export interface Block {
  id: string;
  type: BlockType;
  content: string;
  customStyles?: Partial<StyleConfig>;
}

export interface GeneratedOutput {
  html: string;
  css: string;
}

import { StyleConfig } from './types';

export const DEFAULT_HEADING_STYLE: StyleConfig = {
  color: '#1a202c',
  fontSize: '2rem',
  fontWeight: '700',
  textAlign: 'left',
  padding: '0px',
};

export const DEFAULT_PARAGRAPH_STYLE: StyleConfig = {
  color: '#4a5568',
  fontSize: '1rem',
  fontWeight: '400',
  textAlign: 'left',
  padding: '10px',
  backgroundColor: '#f7fafc',
  borderRadius: '8px'
};

export const PREVIEW_WRAPPER_STYLE = `
  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  max-width: 100%;
  margin: 0 auto;
  padding: 20px;
  box-sizing: border-box;
`;

import React from 'react';
import { Trash2, MoveUp, MoveDown, Type, AlignLeft } from 'lucide-react';
import { Block, BlockType } from '../types';

interface BlockEditorProps {
  block: Block;
  index: number;
  totalBlocks: number;
  onUpdate: (id: string, updates: Partial<Block>) => void;
  onRemove: (id: string) => void;
  onMove: (index: number, direction: 'up' | 'down') => void;
}

export const BlockEditor: React.FC<BlockEditorProps> = ({
  block,
  index,
  totalBlocks,
  onUpdate,
  onRemove,
  onMove,
}) => {
  return (
    <div className="bg-white dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 shadow-sm p-4 transition-all hover:shadow-md">
      <div className="flex justify-between items-center mb-3">
        <div className="flex items-center space-x-2">
          <span className="bg-gray-100 dark:bg-slate-700 text-gray-500 dark:text-gray-400 text-xs font-mono px-2 py-1 rounded">
            #{index + 1}
          </span>
          <div className="flex bg-gray-100 dark:bg-slate-700 rounded-md p-1">
            <button
              onClick={() => onUpdate(block.id, { type: 'heading' })}
              className={`p-1.5 rounded ${
                block.type === 'heading'
                  ? 'bg-white dark:bg-slate-600 shadow-sm text-blue-600 dark:text-blue-400'
                  : 'text-gray-500 hover:text-gray-700 dark:text-gray-400'
              }`}
              title="Heading"
            >
              <Type size={16} />
            </button>
            <button
              onClick={() => onUpdate(block.id, { type: 'paragraph' })}
              className={`p-1.5 rounded ${
                block.type === 'paragraph'
                  ? 'bg-white dark:bg-slate-600 shadow-sm text-blue-600 dark:text-blue-400'
                  : 'text-gray-500 hover:text-gray-700 dark:text-gray-400'
              }`}
              title="Paragraph"
            >
              <AlignLeft size={16} />
            </button>
          </div>
          <span className="text-sm font-medium text-gray-700 dark:text-gray-200 capitalize">
            {block.type}
          </span>
        </div>

        <div className="flex items-center space-x-1">
          <button
            onClick={() => onMove(index, 'up')}
            disabled={index === 0}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-30 disabled:hover:text-gray-400 transition-colors"
            title="Move Up"
          >
            <MoveUp size={16} />
          </button>
          <button
            onClick={() => onMove(index, 'down')}
            disabled={index === totalBlocks - 1}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-30 disabled:hover:text-gray-400 transition-colors"
            title="Move Down"
          >
            <MoveDown size={16} />
          </button>
          <div className="w-px h-4 bg-gray-200 dark:bg-slate-700 mx-1"></div>
          <button
            onClick={() => onRemove(block.id)}
            className="p-1.5 text-gray-400 hover:text-red-500 transition-colors"
            title="Remove Block"
          >
            <Trash2 size={16} />
          </button>
        </div>
      </div>

      <textarea
        value={block.content}
        onChange={(e) => onUpdate(block.id, { content: e.target.value })}
        placeholder={`Enter your ${block.type} text here...`}
        className="w-full p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all min-h-[100px] text-gray-800 dark:text-gray-100 placeholder-gray-400 dark:placeholder-slate-500 resize-y"
      />
    </div>
  );
};

import React from 'react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE } from '../constants';

interface LivePreviewProps {
  blocks: Block[];
}

export const LivePreview: React.FC<LivePreviewProps> = ({ blocks }) => {
  // Helper to convert style object to inline style string for react
  const getStyle = (block: Block): React.CSSProperties => {
    const defaultStyle = block.type === 'heading' ? DEFAULT_HEADING_STYLE : DEFAULT_PARAGRAPH_STYLE;
    // We mix default styles with any custom styles the block might have (future proofing)
    const combined = { ...defaultStyle, ...block.customStyles };

    // Convert to React CSSProperties
    return {
      color: combined.color,
      fontSize: combined.fontSize,
      fontWeight: combined.fontWeight,
      textAlign: combined.textAlign,
      padding: combined.padding,
      backgroundColor: combined.backgroundColor,
      borderRadius: combined.borderRadius,
      marginBottom: block.type === 'heading' ? '1rem' : '1.5rem',
      lineHeight: block.type === 'heading' ? '1.2' : '1.6',
    } as React.CSSProperties;
  };

  if (blocks.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-500 p-8 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg">
        <p className="text-center">No content to preview.</p>
        <p className="text-sm">Add some blocks on the left to get started.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden min-h-[300px]">
      <div className="bg-gray-100 border-b border-gray-200 px-4 py-2 flex items-center space-x-2">
        <div className="flex space-x-1.5">
          <div className="w-3 h-3 rounded-full bg-red-400"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
          <div className="w-3 h-3 rounded-full bg-green-400"></div>
        </div>
        <span className="text-xs text-gray-500 font-medium ml-2">Preview</span>
      </div>
      <div className="p-8 bg-white" style={{ minHeight: '400px' }}>
        {blocks.map((block) => {
          if (block.type === 'heading') {
            return (
              <h2 key={block.id} style={getStyle(block)}>
                {block.content || <span className="opacity-30">Empty Heading</span>}
              </h2>
            );
          }
          return (
            <p key={block.id} style={getStyle(block)}>
              {block.content || <span className="opacity-30">Empty Paragraph</span>}
            </p>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check } from 'lucide-react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, PREVIEW_WRAPPER_STYLE } from '../constants';

interface CodeOutputProps {
  blocks: Block[];
}

export const CodeOutput: React.FC<CodeOutputProps> = ({ blocks }) => {
  const [copied, setCopied] = useState(false);

  const generateCode = (): string => {
    if (blocks.length === 0) return '<!-- Add blocks to generate HTML -->';

    const cssToInline = (style: Record<string, any>) => {
      return Object.entries(style)
        .filter(([_, value]) => value !== undefined)
        .map(([key, value]) => {
          // specific overrides for css string vs react style object
          const cssKey = key.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`);
          return `${cssKey}: ${value}`;
        })
        .join('; ');
    };

    const headingStyle = cssToInline(DEFAULT_HEADING_STYLE);
    const paraStyle = cssToInline(DEFAULT_PARAGRAPH_STYLE);

    let html = `<div style="${PREVIEW_WRAPPER_STYLE.replace(/\n/g, '')}">\n`;

    blocks.forEach(block => {
      if (block.type === 'heading') {
        html += `  <h2 style="${headingStyle}; margin-bottom: 1rem; line-height: 1.2;">${block.content}</h2>\n`;
      } else {
        html += `  <p style="${paraStyle}; margin-bottom: 1.5rem; line-height: 1.6;">${block.content}</p>\n`;
      }
    });

    html += `</div>`;
    return html;
  };

  const code = generateCode();

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="relative group rounded-lg overflow-hidden border border-gray-200 dark:border-slate-700 bg-gray-900 dark:bg-black text-gray-300">
      <div className="absolute top-2 right-2">
        <button
          onClick={handleCopy}
          className="flex items-center space-x-1.5 px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-white text-xs rounded-md transition-colors border border-gray-700"
        >
          {copied ? <Check size={14} className="text-green-400" /> : <Copy size={14} />}
          <span>{copied ? 'Copied!' : 'Copy Code'}</span>
        </button>
      </div>
      <div className="p-4 overflow-x-auto">
        <pre className="font-mono text-sm leading-relaxed whitespace-pre-wrap">
          <code className="language-html">{code}</code>
        </pre>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Plus, Code2, Layers, Layout, Moon, Sun, MonitorPlay, FileCode } from 'lucide-react';
import { Block, BlockType } from './types';
import { BlockEditor } from './components/BlockEditor';
import { LivePreview } from './components/LivePreview';
import { CodeOutput } from './components/CodeOutput';

const App: React.FC = () => {
  const [blocks, setBlocks] = useState<Block[]>([
    { id: '1', type: 'heading', content: 'Welcome to the Generator' },
    { id: '2', type: 'paragraph', content: 'Start by editing this text or adding new blocks to generate your HTML.' }
  ]);
  const [activeTab, setActiveTab] = useState<'preview' | 'code'>('preview');
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    // Check system preference or localStorage
    const isDark = localStorage.getItem('theme') === 'dark' || 
      (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches);
    setDarkMode(isDark);
    if (isDark) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, []);

  const toggleTheme = () => {
    setDarkMode(!darkMode);
    if (!darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  const addBlock = (type: BlockType) => {
    const newBlock: Block = {
      id: Date.now().toString(),
      type,
      content: '',
    };
    setBlocks([...blocks, newBlock]);
  };

  const updateBlock = (id: string, updates: Partial<Block>) => {
    setBlocks(blocks.map(b => b.id === id ? { ...b, ...updates } : b));
  };

  const removeBlock = (id: string) => {
    setBlocks(blocks.filter(b => b.id !== id));
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    const newBlocks = [...blocks];
    if (direction === 'up' && index > 0) {
      [newBlocks[index], newBlocks[index - 1]] = [newBlocks[index - 1], newBlocks[index]];
    } else if (direction === 'down' && index < newBlocks.length - 1) {
      [newBlocks[index], newBlocks[index + 1]] = [newBlocks[index + 1], newBlocks[index]];
    }
    setBlocks(newBlocks);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900 dark:selection:bg-blue-900 dark:selection:text-blue-100">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-gray-200 dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-blue-600 rounded-lg">
              <Code2 className="text-white" size={20} />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
              HTML/CSS Generator
            </h1>
          </div>

          <div className="flex items-center space-x-4">
            <button
              onClick={toggleTheme}
              className="p-2 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg transition-colors"
              aria-label="Toggle theme"
            >
              {darkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
            <a 
              href="#" 
              className="hidden sm:block text-sm font-medium text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200 transition-colors"
            >
              Docs
            </a>
            <button className="bg-gray-900 dark:bg-white text-white dark:text-gray-900 px-4 py-2 rounded-lg text-sm font-medium hover:bg-gray-800 dark:hover:bg-gray-100 transition-colors shadow-sm">
              Export
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 lg:p-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full">

          {/* Left Column: Editor */}
          <div className="flex flex-col space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-2 text-gray-700 dark:text-gray-200">
                <Layers size={20} />
                <h2 className="text-lg font-semibold">Structure</h2>
              </div>
              <span className="text-sm text-gray-500 dark:text-gray-400">
                {blocks.length} {blocks.length === 1 ? 'Block' : 'Blocks'}
              </span>
            </div>

            <div className="space-y-4">
              {blocks.map((block, index) => (
                <BlockEditor
                  key={block.id}
                  block={block}
                  index={index}
                  totalBlocks={blocks.length}
                  onUpdate={updateBlock}
                  onRemove={removeBlock}
                  onMove={moveBlock}
                />
              ))}

              {blocks.length === 0 && (
                <div className="text-center py-12 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg bg-gray-50 dark:bg-slate-800/50">
                  <p className="text-gray-500 dark:text-gray-400 mb-2">No blocks yet</p>
                  <p className="text-sm text-gray-400 dark:text-gray-500">Add a heading or paragraph to start</p>
                </div>
              )}
            </div>

            <div className="pt-4 border-t border-gray-200 dark:border-slate-800">
              <h3 className="text-sm font-medium text-gray-500 dark:text-gray-400 mb-3 uppercase tracking-wider">
                Add New Block
              </h3>
              <div className="grid grid-cols-2 gap-3">
                <button
                  onClick={() => addBlock('heading')}
                  className="flex items-center justify-center space-x-2 p-3 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-blue-500 dark:hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 rounded-lg transition-all group shadow-sm hover:shadow"
                >
                  <Plus size={18} className="text-gray-400 group-hover:text-blue-500 transition-colors" />
                  <span className="font-medium text-gray-700 dark:text-gray-200 group-hover:text-blue-600 dark:group-hover:text-blue-400">Heading</span>
                </button>
                <button
                  onClick={() => addBlock('paragraph')}
                  className="flex items-center justify-center space-x-2 p-3 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-blue-500 dark:hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 rounded-lg transition-all group shadow-sm hover:shadow"
                >
                  <Plus size={18} className="text-gray-400 group-hover:text-blue-500 transition-colors" />
                  <span className="font-medium text-gray-700 dark:text-gray-200 group-hover:text-blue-600 dark:group-hover:text-blue-400">Paragraph</span>
                </button>
              </div>
            </div>
          </div>

          {/* Right Column: Preview/Code */}
          <div className="lg:sticky lg:top-24 h-fit flex flex-col space-y-4">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-gray-200 dark:border-slate-700 overflow-hidden">
              <div className="flex border-b border-gray-200 dark:border-slate-700">
                <button
                  onClick={() => setActiveTab('preview')}
                  className={`flex-1 flex items-center justify-center space-x-2 py-3 text-sm font-medium transition-colors ${
                    activeTab === 'preview'
                      ? 'bg-gray-50 dark:bg-slate-700/50 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600'
                      : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-50 dark:hover:bg-slate-800'
                  }`}
                >
                  <MonitorPlay size={16} />
                  <span>Live Preview</span>
                </button>
                <button
                  onClick={() => setActiveTab('code')}
                  className={`flex-1 flex items-center justify-center space-x-2 py-3 text-sm font-medium transition-colors ${
                    activeTab === 'code'
                      ? 'bg-gray-50 dark:bg-slate-700/50 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600'
                      : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-50 dark:hover:bg-slate-800'
                  }`}
                >
                  <FileCode size={16} />
                  <span>Generated HTML</span>
                </button>
              </div>

              <div className="p-4 bg-gray-50 dark:bg-slate-900/50">
                {activeTab === 'preview' ? (
                  <LivePreview blocks={blocks} />
                ) : (
                  <CodeOutput blocks={blocks} />
                )}
              </div>
            </div>

            <div className="bg-blue-50 dark:bg-blue-900/20 rounded-lg p-4 border border-blue-100 dark:border-blue-900/50">
              <div className="flex items-start space-x-3">
                <Layout className="text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" size={20} />
                <div>
                  <h4 className="text-sm font-semibold text-blue-800 dark:text-blue-300">Quick Tip</h4>
                  <p className="text-xs text-blue-700 dark:text-blue-400 mt-1">
                    The generated HTML includes inline CSS for maximum portability. You can copy the code directly into emails, CMS editors, or any HTML file.
                  </p>
                </div>
              </div>
            </div>
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

export type BlockType = 'heading' | 'paragraph' | 'wrapper';

export interface StyleConfig {
  color?: string;
  fontSize?: string;
  backgroundColor?: string;
  padding?: string;
  borderRadius?: string;
  fontWeight?: string;
  textAlign?: 'left' | 'center' | 'right';
  border?: string;
}

export interface Block {
  id: string;
  type: BlockType;
  content: string; // For wrapper, this might be a label or unused
  children?: Block[]; // Nested blocks for wrappers
  customStyles?: Partial<StyleConfig>;
}

export interface GeneratedOutput {
  html: string;
  css: string;
}

import { StyleConfig } from './types';

export const DEFAULT_HEADING_STYLE: StyleConfig = {
  color: '#1a202c',
  fontSize: '2rem',
  fontWeight: '700',
  textAlign: 'left',
  padding: '0px',
};

export const DEFAULT_PARAGRAPH_STYLE: StyleConfig = {
  color: '#4a5568',
  fontSize: '1rem',
  fontWeight: '400',
  textAlign: 'left',
  padding: '10px',
  backgroundColor: '#f7fafc',
  borderRadius: '8px'
};

export const DEFAULT_WRAPPER_STYLE: StyleConfig = {
  backgroundColor: '#eff6ff', // Light blue background
  padding: '24px',
  borderRadius: '12px',
  border: '1px solid #dbeafe', // Subtle blue border
};

export const PREVIEW_WRAPPER_STYLE = `
  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  max-width: 100%;
  margin: 0 auto;
  padding: 20px;
  box-sizing: border-box;
`;

import React from 'react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, DEFAULT_WRAPPER_STYLE } from '../constants';

interface LivePreviewProps {
  blocks: Block[];
}

export const LivePreview: React.FC<LivePreviewProps> = ({ blocks }) => {
  // Helper to convert style object to inline style string for react
  const getStyle = (block: Block): React.CSSProperties => {
    let defaultStyle = {};
    if (block.type === 'heading') defaultStyle = DEFAULT_HEADING_STYLE;
    else if (block.type === 'paragraph') defaultStyle = DEFAULT_PARAGRAPH_STYLE;
    else if (block.type === 'wrapper') defaultStyle = DEFAULT_WRAPPER_STYLE;

    const combined = { ...defaultStyle, ...block.customStyles };

    const baseStyle: React.CSSProperties = {
      color: combined.color,
      fontSize: combined.fontSize,
      fontWeight: combined.fontWeight,
      textAlign: combined.textAlign,
      padding: combined.padding,
      backgroundColor: combined.backgroundColor,
      borderRadius: combined.borderRadius,
      border: combined.border,
      marginBottom: block.type === 'heading' ? '1rem' : block.type === 'wrapper' ? '2rem' : '1.5rem',
      lineHeight: block.type === 'heading' ? '1.2' : '1.6',
      boxSizing: 'border-box',
    };

    return baseStyle;
  };

  const renderBlock = (block: Block) => {
    if (block.type === 'heading') {
      return (
        <h2 key={block.id} style={getStyle(block)}>
          {block.content || <span className="opacity-30">Empty Heading</span>}
        </h2>
      );
    }

    if (block.type === 'wrapper') {
      return (
        <div key={block.id} style={getStyle(block)}>
          {block.children && block.children.length > 0 ? (
            block.children.map(renderBlock)
          ) : (
            <div className="text-gray-400 text-sm text-center italic border-2 border-dashed border-gray-300/50 p-4 rounded">
              Empty Wrapper
            </div>
          )}
        </div>
      );
    }

    return (
      <p key={block.id} style={getStyle(block)}>
        {block.content || <span className="opacity-30">Empty Paragraph</span>}
      </p>
    );
  };

  if (blocks.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-500 p-8 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg">
        <p className="text-center">No content to preview.</p>
        <p className="text-sm">Add some blocks on the left to get started.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden min-h-[300px]">
      <div className="bg-gray-100 border-b border-gray-200 px-4 py-2 flex items-center space-x-2">
        <div className="flex space-x-1.5">
