  return (
    <div className={`
      relative rounded-lg border shadow-sm transition-all
      ${isWrapper 
        ? 'bg-blue-50/50 dark:bg-blue-900/10 border-blue-200 dark:border-blue-800 p-4 pb-6' 
        : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 p-4 hover:shadow-md'
