import React from 'react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, DEFAULT_WRAPPER_STYLE, DEFAULT_LINK_STYLE, DEFAULT_IMAGE_STYLE } from '../constants';

interface LivePreviewProps {
  blocks: Block[];
}

export const LivePreview: React.FC<LivePreviewProps> = ({ blocks }) => {
  const getStyle = (block: Block): React.CSSProperties => {
    let defaultStyle = {};
    if (block.type === 'heading') defaultStyle = DEFAULT_HEADING_STYLE;
    else if (block.type === 'paragraph') defaultStyle = DEFAULT_PARAGRAPH_STYLE;
    else if (block.type === 'wrapper') defaultStyle = DEFAULT_WRAPPER_STYLE;
    else if (block.type === 'link') defaultStyle = DEFAULT_LINK_STYLE;
    else if (block.type === 'image') defaultStyle = DEFAULT_IMAGE_STYLE;

    const combined = { ...defaultStyle, ...block.customStyles };

    // Wrapper specific layout styles
    const layoutStyles: React.CSSProperties = {};
    if (block.type === 'wrapper' && block.layout === 'columns') {
      layoutStyles.display = 'grid';
      layoutStyles.gridTemplateColumns = '1fr 1fr';
      layoutStyles.gap = '1.5rem';
      layoutStyles.alignItems = 'start';
    }

    const baseStyle: React.CSSProperties = {
      ...combined,
      ...layoutStyles,
      marginBottom: block.type === 'heading' ? '1rem' : block.type === 'wrapper' ? '2rem' : '1.5rem',
      lineHeight: block.type === 'heading' ? '1.2' : '1.6',
      boxSizing: 'border-box',
    };

    return baseStyle;
  };

  const renderBlock = (block: Block) => {
    // HEADING
    if (block.type === 'heading') {
      return (
        <h2 key={block.id} style={getStyle(block)}>
          {block.content || <span className="opacity-30">Empty Heading</span>}
        </h2>
      );
    }

    // WRAPPER
    if (block.type === 'wrapper') {
      const style = getStyle(block);
      // If we are in grid mode, we need to ensure children don't have large margins that break alignment visually
      // but strictly speaking, CSS grid handles margins well.

      return (
        <div key={block.id} style={style}>
          {block.children && block.children.length > 0 ? (
            block.children.map((child) => (
              // If grid is active, wrap children in a div if necessary? 
              // Actually, standard rendering is fine, but we might want to suppress the bottom margin of the last elements if we were strict.
              // For now, simple rendering is enough.
              <div key={child.id} style={{ height: '100%' }}>
                 {renderBlock(child)}
              </div>
            ))
          ) : (
             // Span full width if empty
            <div style={{ gridColumn: '1 / -1' }} className="text-gray-400 text-sm text-center italic border-2 border-dashed border-gray-300/50 p-4 rounded">
              Empty Wrapper
            </div>
          )}
        </div>
      );
    }

    // LINK
    if (block.type === 'link') {
      return (
        <div key={block.id} style={{ marginBottom: '1.5rem' }}>
          <a href={block.url || '#'} style={getStyle(block)}>
            {block.content || 'Link Text'}
          </a>
        </div>
      );
    }

    // IMAGE
    if (block.type === 'image') {
      const style = getStyle(block);

      if (block.imageMode === 'canvas') {
        return (
          <div key={block.id} style={{ ...style, backgroundColor: '#e2e8f0', minHeight: '200px', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px dashed #cbd5e1' }}>
            <div style={{ textAlign: 'center', color: '#94a3b8' }}>
              <span style={{ fontSize: '24px', fontWeight: 'bold', display: 'block' }}>IMAGE CANVAS</span>
              <span style={{ fontSize: '14px' }}>{block.alt || 'Placeholder'}</span>
            </div>
          </div>
        );
      }

      return (
        <img 
          key={block.id} 
          src={block.url || ''} 
          alt={block.alt || ''} 
          style={style} 
          onError={(e) => {
            const target = e.target as HTMLImageElement;
            target.style.display = 'none';
            if (target.parentElement) {
              const errorMsg = document.createElement('div');
              errorMsg.innerText = "Invalid Image URL";
              errorMsg.style.color = "red";
              errorMsg.style.fontSize = "12px";
              errorMsg.style.padding = "10px";
              errorMsg.style.border = "1px solid red";
              target.parentElement.appendChild(errorMsg);
            }
          }}
        />
      );
    }

    // PARAGRAPH (Default)
    return (
      <p key={block.id} style={getStyle(block)}>
        {block.content || <span className="opacity-30">Empty Paragraph</span>}
      </p>
    );
  };

  if (blocks.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-500 p-8 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg">
        <p className="text-center">No content to preview.</p>
        <p className="text-sm">Add some blocks on the left to get started.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden min-h-[300px]">
      <div className="bg-gray-100 border-b border-gray-200 px-4 py-2 flex items-center space-x-2">
        <div className="flex space-x-1.5">
          <div className="w-3 h-3 rounded-full bg-red-400"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
          <div className="w-3 h-3 rounded-full bg-green-400"></div>
        </div>
        <span className="text-xs text-gray-500 font-medium ml-2">Preview</span>
      </div>
      <div className="p-8 bg-white" style={{ minHeight: '400px' }}>
        {blocks.map(renderBlock)}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check } from 'lucide-react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, DEFAULT_WRAPPER_STYLE, DEFAULT_LINK_STYLE, DEFAULT_IMAGE_STYLE, PREVIEW_WRAPPER_STYLE } from '../constants';

interface CodeOutputProps {
  blocks: Block[];
}

export const CodeOutput: React.FC<CodeOutputProps> = ({ blocks }) => {
  const [copied, setCopied] = useState(false);

  const cssToInline = (style: Record<string, any>) => {
    return Object.entries(style)
      .filter(([_, value]) => value !== undefined)
      .map(([key, value]) => {
        const cssKey = key.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`);
        return `${cssKey}: ${value}`;
      })
      .join('; ');
  };

  const getBlockStyle = (block: Block) => {
    let defaultStyle = {};
    if (block.type === 'heading') defaultStyle = DEFAULT_HEADING_STYLE;
    else if (block.type === 'paragraph') defaultStyle = DEFAULT_PARAGRAPH_STYLE;
    else if (block.type === 'wrapper') defaultStyle = DEFAULT_WRAPPER_STYLE;
    else if (block.type === 'link') defaultStyle = DEFAULT_LINK_STYLE;
    else if (block.type === 'image') defaultStyle = DEFAULT_IMAGE_STYLE;

    return cssToInline({ ...defaultStyle, ...block.customStyles });
  };

  const generateBlockHtml = (block: Block, indentLevel: number = 2): string => {
    const indent = '  '.repeat(indentLevel);
    const style = getBlockStyle(block);

    // HEADING
    if (block.type === 'heading') {
      return `${indent}<h2 style="${style}; margin-bottom: 1rem; line-height: 1.2;">${block.content}</h2>\n`;
    }

    // WRAPPER
    if (block.type === 'wrapper') {
      let layoutStyles = '';
      if (block.layout === 'columns') {
        layoutStyles = ' display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; align-items: start;';
      }

      let wrapperHtml = `${indent}<div style="${style};${layoutStyles} margin-bottom: 2rem;">\n`;
      if (block.children && block.children.length > 0) {
        block.children.forEach(child => {
           // If grid, we might technically want to wrap child in div to ensure correct cell placement if child is complex, 
           // but for simple use case, direct placement is usually preferred to reduce DOM depth. 
           // However, to match Preview which wraps in div for height consistency:
           if (block.layout === 'columns') {
             wrapperHtml += `${indent}  <div style="height: 100%;">\n`;
             wrapperHtml += generateBlockHtml(child, indentLevel + 2);
             wrapperHtml += `${indent}  </div>\n`;
           } else {
             wrapperHtml += generateBlockHtml(child, indentLevel + 1);
           }
        });
      }
      wrapperHtml += `${indent}</div>\n`;
      return wrapperHtml;
    }

    // LINK
    if (block.type === 'link') {
      return `${indent}<div style="margin-bottom: 1.5rem;"><a href="${block.url || '#'}" style="${style}">${block.content || 'Link Text'}</a></div>\n`;
    }

    // IMAGE
    if (block.type === 'image') {
      if (block.imageMode === 'canvas') {
        const placeholderStyle = `background-color: #e2e8f0; min-height: 200px; display: flex; align-items: center; justify-content: center; border: 2px dashed #cbd5e1; color: #94a3b8; font-family: sans-serif; font-weight: bold;`;
        return `${indent}<div style="${style}; ${placeholderStyle} margin-bottom: 1.5rem;">${block.alt || 'IMAGE CANVAS'}</div>\n`;
      }
      return `${indent}<img src="${block.url || ''}" alt="${block.alt || ''}" style="${style}; margin-bottom: 1.5rem;" />\n`;
    }

    // PARAGRAPH
    return `${indent}<p style="${style}; margin-bottom: 1.5rem; line-height: 1.6;">${block.content}</p>\n`;
  };

  const generateCode = (): string => {
    if (blocks.length === 0) return '<!-- Add blocks to generate HTML -->';

    let html = `<div style="${PREVIEW_WRAPPER_STYLE.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim()}">\n`;
    blocks.forEach(block => {
      html += generateBlockHtml(block);
    });
    html += `</div>`;
    return html;
  };

  const code = generateCode();

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="relative group rounded-lg overflow-hidden border border-gray-200 dark:border-slate-700 bg-gray-900 dark:bg-black text-gray-300">
      <div className="absolute top-2 right-2">
        <button
          onClick={handleCopy}
          className="flex items-center space-x-1.5 px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-white text-xs rounded-md transition-colors border border-gray-700"
        >
          {copied ? <Check size={14} className="text-green-400" /> : <Copy size={14} />}
          <span>{copied ? 'Copied!' : 'Copy Code'}</span>
        </button>
      </div>
      <div className="p-4 overflow-x-auto">
        <pre className="font-mono text-sm leading-relaxed whitespace-pre-wrap">
          <code className="language-html">{code}</code>
        </pre>
      </div>
    </div>
  );
};

export type BlockType = 'heading' | 'paragraph' | 'wrapper' | 'image' | 'link' | 'nav';

export interface StyleConfig {
  color?: string;
  fontSize?: string;
  backgroundColor?: string;
  padding?: string;
  borderRadius?: string;
  fontWeight?: string;
  textAlign?: 'left' | 'center' | 'right';
  border?: string;
  width?: string;
  height?: string;
  display?: string;
  gap?: string;
  alignItems?: string;
  textDecoration?: string;
  borderBottom?: string;
}

export interface Block {
  id: string;
  type: BlockType;
  content: string; // Heading/Para/Link text. Unused for Image (uses alt/url)
  children?: Block[]; // Nested blocks for wrappers/nav
  customStyles?: Partial<StyleConfig>;

  // New properties for Link and Image
  url?: string;       // href for Links, src for Images
  alt?: string;       // alt text for Images
  imageMode?: 'url' | 'canvas'; // 'url' for actual image, 'canvas' for skeleton

  // New properties for Wrapper
  layout?: 'stack' | 'columns'; 

  // New property for Headings (Anchor Target)
  htmlId?: string;
}

export interface GeneratedOutput {
  html: string;
  css: string;
}

import { StyleConfig } from './types';

export const DEFAULT_HEADING_STYLE: StyleConfig = {
  color: '#1a202c',
  fontSize: '2rem',
  fontWeight: '700',
  textAlign: 'left',
  padding: '0px',
};

export const DEFAULT_PARAGRAPH_STYLE: StyleConfig = {
  color: '#4a5568',
  fontSize: '1rem',
  fontWeight: '400',
  textAlign: 'left',
  padding: '10px',
  backgroundColor: '#f7fafc',
  borderRadius: '8px'
};

export const DEFAULT_WRAPPER_STYLE: StyleConfig = {
  backgroundColor: '#eff6ff', // Light blue background
  padding: '24px',
  borderRadius: '12px',
  border: '1px solid #dbeafe', // Subtle blue border
};

export const DEFAULT_NAV_STYLE: StyleConfig = {
  padding: '16px',
  backgroundColor: '#ffffff',
  borderBottom: '1px solid #e2e8f0',
  display: 'flex',
  gap: '24px',
  alignItems: 'center'
};

export const DEFAULT_LINK_STYLE: StyleConfig = {
  color: '#2563eb', // Blue-600
  fontSize: '1rem',
  fontWeight: '500',
  textDecoration: 'underline',
  padding: '0px',
  display: 'inline-block',
};

export const DEFAULT_IMAGE_STYLE: StyleConfig = {
  width: '100%',
  borderRadius: '8px',
  display: 'block',
};

export const PREVIEW_WRAPPER_STYLE = `
  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  max-width: 100%;
  margin: 0 auto;
  padding: 20px;
  box-sizing: border-box;
`;

import React from 'react';
import { Trash2, MoveUp, MoveDown, Type, AlignLeft, Box, Plus, Image as ImageIcon, Link as LinkIcon, Globe, LayoutTemplate, Columns, Rows, Navigation, Hash } from 'lucide-react';
import { Block, BlockType } from '../types';

interface BlockEditorProps {
  block: Block;
  index: number;
  totalBlocks: number;
  onUpdate: (id: string, updates: Partial<Block>) => void;
  onRemove: (id: string) => void;
  onMove: (id: string, direction: 'up' | 'down') => void;
  onAddChild: (parentId: string, type: BlockType) => void;
}

export const BlockEditor: React.FC<BlockEditorProps> = ({
  block,
  index,
  totalBlocks,
  onUpdate,
  onRemove,
  onMove,
  onAddChild,
}) => {
  const isWrapper = block.type === 'wrapper';
  const isNav = block.type === 'nav';
  const isContainer = isWrapper || isNav;
  const isImage = block.type === 'image';
  const isLink = block.type === 'link';
  const isHeading = block.type === 'heading';

  const getTypeIcon = (type: BlockType) => {
    switch (type) {
      case 'heading': return <Type size={16} />;
      case 'paragraph': return <AlignLeft size={16} />;
      case 'wrapper': return <Box size={16} />;
      case 'nav': return <Navigation size={16} />;
      case 'image': return <ImageIcon size={16} />;
      case 'link': return <LinkIcon size={16} />;
    }
  };

  return (
    <div className={`
      relative rounded-lg border shadow-sm transition-all
      ${isContainer 
        ? isNav 
          ? 'bg-slate-50/50 dark:bg-slate-900/10 border-slate-200 dark:border-slate-800 p-4 pb-6'
          : 'bg-blue-50/50 dark:bg-blue-900/10 border-blue-200 dark:border-blue-800 p-4 pb-6' 
        : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 p-4 hover:shadow-md'
      }
    `}>
      {/* Block Header */}
      <div className="flex justify-between items-center mb-3">
        <div className="flex items-center space-x-2">
          <span className={`text-xs font-mono px-2 py-1 rounded ${
            isContainer 
              ? 'bg-blue-100 dark:bg-blue-900 text-blue-700 dark:text-blue-300' 
              : 'bg-gray-100 dark:bg-slate-700 text-gray-500 dark:text-gray-400'
          }`}>
            #{index + 1}
          </span>

          {/* Type Selector */}
          <div className="flex bg-gray-100 dark:bg-slate-700 rounded-md p-1 space-x-0.5">
            {(['heading', 'paragraph', 'link', 'image', 'wrapper', 'nav'] as BlockType[]).map((t) => (
              <button
                key={t}
                onClick={() => onUpdate(block.id, { 
                  type: t, 
                  children: (t === 'wrapper' || t === 'nav') ? block.children || [] : undefined,
                  imageMode: t === 'image' && !block.imageMode ? 'url' : block.imageMode
                })}
                className={`p-1.5 rounded transition-all ${
                  block.type === t 
                    ? 'bg-white dark:bg-slate-600 shadow-sm text-blue-600 dark:text-blue-400 scale-105' 
                    : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-300'
                }`}
                title={t.charAt(0).toUpperCase() + t.slice(1)}
              >
                {getTypeIcon(t)}
              </button>
            ))}
          </div>
          <span className="text-sm font-medium text-gray-700 dark:text-gray-200 capitalize hidden sm:inline-block">
            {block.type}
          </span>
        </div>

        {/* Action Buttons */}
        <div className="flex items-center space-x-1">
          <button
            onClick={() => onMove(block.id, 'up')}
            disabled={index === 0}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-30 transition-colors"
          >
            <MoveUp size={16} />
          </button>
          <button
            onClick={() => onMove(block.id, 'down')}
            disabled={index === totalBlocks - 1}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-30 transition-colors"
          >
            <MoveDown size={16} />
          </button>
          <div className="w-px h-4 bg-gray-200 dark:bg-slate-700 mx-1"></div>
          <button
            onClick={() => onRemove(block.id)}
            className="p-1.5 text-gray-400 hover:text-red-500 transition-colors"
          >
            <Trash2 size={16} />
          </button>
        </div>
      </div>

      {/* Editor Content */}
      <div className="space-y-3">

        {/* HEADING EXTRAS (ID) */}
        {isHeading && (
          <div className="flex items-center space-x-2 mb-2">
            <div className="relative flex-1">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                <Hash size={14} />
              </div>
              <input
                type="text"
                value={block.htmlId || ''}
                onChange={(e) => onUpdate(block.id, { htmlId: e.target.value })}
                placeholder="Anchor ID (e.g. 'about-us')"
                className="w-full pl-9 p-2 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-xs font-mono text-gray-700 dark:text-gray-200"
              />
            </div>
            <div className="text-[10px] text-gray-400 max-w-[150px] leading-tight">
              Set this ID to link here from the Nav (e.g. href="#about-us")
            </div>
          </div>
        )}

        {/* IMAGE EDITOR */}
        {isImage && (
          <div className="space-y-3">
            <div className="flex space-x-2 bg-gray-50 dark:bg-slate-900/50 p-1 rounded-lg w-fit border border-gray-200 dark:border-slate-700">
              <button
                onClick={() => onUpdate(block.id, { imageMode: 'url' })}
                className={`flex items-center space-x-2 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                  block.imageMode === 'url' || !block.imageMode
                    ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' 
                    : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                }`}
              >
                <Globe size={14} />
                <span>HTTPS Link</span>
              </button>
              <button
                onClick={() => onUpdate(block.id, { imageMode: 'canvas' })}
                className={`flex items-center space-x-2 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                  block.imageMode === 'canvas'
                    ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' 
                    : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                }`}
              >
                <LayoutTemplate size={14} />
                <span>Canvas Skeleton</span>
              </button>
            </div>

            {block.imageMode === 'url' || !block.imageMode ? (
              <input
                type="text"
                value={block.url || ''}
                onChange={(e) => onUpdate(block.id, { url: e.target.value })}
                placeholder="https://example.com/image.jpg"
                className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm font-mono text-gray-700 dark:text-gray-200"
              />
            ) : (
              <div className="text-xs text-gray-500 dark:text-gray-400 italic px-1">
                A placeholder box will be generated. No URL needed.
              </div>
            )}

            <input
              type="text"
              value={block.alt || ''}
              onChange={(e) => onUpdate(block.id, { alt: e.target.value })}
              placeholder="Alt text (description for accessibility)"
              className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm text-gray-700 dark:text-gray-200"
            />
          </div>
        )}

        {/* LINK EDITOR */}
        {isLink && (
          <div className="space-y-3">
             <input
              type="text"
              value={block.content}
              onChange={(e) => onUpdate(block.id, { content: e.target.value })}
              placeholder="Link Text (e.g. 'Click Here')"
              className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm font-medium text-gray-700 dark:text-gray-200"
            />
            <input
              type="text"
              value={block.url || ''}
              onChange={(e) => onUpdate(block.id, { url: e.target.value })}
              placeholder="URL or #anchor (e.g. #about)"
              className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm font-mono text-gray-700 dark:text-gray-200"
            />
          </div>
        )}

        {/* CONTAINER EDITOR (WRAPPER / NAV) */}
        {isContainer && (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div className={`text-xs font-medium px-1 ${isNav ? 'text-slate-600 dark:text-slate-400' : 'text-blue-600 dark:text-blue-400'}`}>
                {isNav ? 'Navigation Links' : 'Wrapper Layout'}
              </div>
            </div>

            {/* Layout Toggle for Wrapper only */}
            {isWrapper && (
              <div className="flex bg-white dark:bg-slate-800 p-1 rounded-lg border border-gray-200 dark:border-slate-700 w-fit">
                <button
                  onClick={() => onUpdate(block.id, { layout: 'stack' })}
                  className={`flex items-center space-x-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                    block.layout !== 'columns'
                      ? 'bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 shadow-sm' 
                      : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                  }`}
                >
                  <Rows size={14} />
                  <span>Stack</span>
                </button>
                <button
                  onClick={() => onUpdate(block.id, { layout: 'columns' })}
                  className={`flex items-center space-x-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                    block.layout === 'columns'
                      ? 'bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 shadow-sm' 
                      : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                  }`}
                >
                  <Columns size={14} />
                  <span>2 Columns</span>
                </button>
              </div>
            )}

            <div className={`space-y-4 pl-4 border-l-2 ${isNav ? 'border-slate-200 dark:border-slate-700' : 'border-blue-200 dark:border-blue-800'}`}>
              {block.children && block.children.length > 0 ? (
                block.children.map((childBlock, childIndex) => (
                  <BlockEditor
                    key={childBlock.id}
                    block={childBlock}
                    index={childIndex}
                    totalBlocks={block.children!.length}
                    onUpdate={onUpdate}
                    onRemove={onRemove}
                    onMove={onMove}
                    onAddChild={onAddChild}
                  />
                ))
              ) : (
                <div className={`p-4 border-2 border-dashed rounded-lg text-center text-sm ${isNav ? 'border-slate-200 dark:border-slate-800 text-slate-400' : 'border-blue-200 dark:border-blue-900 text-blue-400'}`}>
                  {isNav ? 'Add links to your navigation bar' : 'Wrapper is empty'}
                </div>
              )}
            </div>

            <div className="flex flex-wrap gap-2 mt-2">
              {isNav ? (
                <button
                  onClick={() => onAddChild(block.id, 'link')}
                  className="flex items-center space-x-1 py-1.5 px-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 text-xs rounded hover:bg-slate-50 dark:hover:bg-slate-800/80 transition-colors shadow-sm"
                >
                  <Plus size={12} />
                  <span>Add Link</span>
                </button>
              ) : (
                (['heading', 'paragraph', 'image', 'link'] as BlockType[]).map(type => (
                   <button
                   key={type}
                   onClick={() => onAddChild(block.id, type)}
                   className="flex items-center space-x-1 py-1.5 px-3 bg-white dark:bg-slate-800 border border-blue-200 dark:border-blue-800 text-blue-600 dark:text-blue-400 text-xs rounded hover:bg-blue-50 dark:hover:bg-blue-900/30 transition-colors"
                 >
                   <Plus size={12} />
                   <span className="capitalize">{type}</span>
                 </button>
                ))
              )}
            </div>
          </div>
        )}

        {/* TEXT EDITOR (Heading/Paragraph) */}
        {!isContainer && !isImage && !isLink && (
          <textarea
            value={block.content}
            onChange={(e) => onUpdate(block.id, { content: e.target.value })}
            placeholder={`Enter your ${block.type} text here...`}
            className="w-full p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all min-h-[100px] text-gray-800 dark:text-gray-100 placeholder-gray-400 dark:placeholder-slate-500 resize-y text-sm"
          />
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, DEFAULT_WRAPPER_STYLE, DEFAULT_LINK_STYLE, DEFAULT_IMAGE_STYLE, DEFAULT_NAV_STYLE } from '../constants';

interface LivePreviewProps {
  blocks: Block[];
}

export const LivePreview: React.FC<LivePreviewProps> = ({ blocks }) => {
  const getStyle = (block: Block): React.CSSProperties => {
    let defaultStyle = {};
    if (block.type === 'heading') defaultStyle = DEFAULT_HEADING_STYLE;
    else if (block.type === 'paragraph') defaultStyle = DEFAULT_PARAGRAPH_STYLE;
    else if (block.type === 'wrapper') defaultStyle = DEFAULT_WRAPPER_STYLE;
    else if (block.type === 'nav') defaultStyle = DEFAULT_NAV_STYLE;
    else if (block.type === 'link') defaultStyle = DEFAULT_LINK_STYLE;
    else if (block.type === 'image') defaultStyle = DEFAULT_IMAGE_STYLE;

    const combined = { ...defaultStyle, ...block.customStyles };

    // Wrapper specific layout styles
    const layoutStyles: React.CSSProperties = {};
    if (block.type === 'wrapper' && block.layout === 'columns') {
      layoutStyles.display = 'grid';
      layoutStyles.gridTemplateColumns = '1fr 1fr';
      layoutStyles.gap = '1.5rem';
      layoutStyles.alignItems = 'start';
    }

    const baseStyle: React.CSSProperties = {
      ...combined,
      ...layoutStyles,
      marginBottom: (block.type === 'heading' || block.type === 'nav') ? '1rem' : block.type === 'wrapper' ? '2rem' : '1.5rem',
      lineHeight: block.type === 'heading' ? '1.2' : '1.6',
      boxSizing: 'border-box',
    };

    return baseStyle;
  };

  const renderBlock = (block: Block) => {
    // HEADING
    if (block.type === 'heading') {
      return (
        <h2 key={block.id} id={block.htmlId} style={getStyle(block)}>
          {block.content || <span className="opacity-30">Empty Heading</span>}
        </h2>
      );
    }

    // WRAPPER & NAV
    if (block.type === 'wrapper' || block.type === 'nav') {
      const style = getStyle(block);
      const ContainerTag = block.type === 'nav' ? 'nav' : 'div';

      return (
        <ContainerTag key={block.id} style={style}>
          {block.children && block.children.length > 0 ? (
            block.children.map((child) => (
              <div key={child.id} style={block.layout === 'columns' ? { height: '100%' } : undefined}>
                 {renderBlock(child)}
              </div>
            ))
          ) : (
            <div style={{ gridColumn: '1 / -1', width: '100%' }} className={`text-sm text-center italic border-2 border-dashed p-4 rounded ${block.type === 'nav' ? 'border-slate-300/50 text-slate-400' : 'border-blue-200 text-blue-400'}`}>
              {block.type === 'nav' ? 'Empty Nav Bar' : 'Empty Wrapper'}
            </div>
          )}
        </ContainerTag>
      );
    }

    // LINK
    if (block.type === 'link') {
      return (
        <div key={block.id} style={{ marginBottom: '0' /* links in navs shouldn't have bottom margin usually, but let's keep it safe */ }}>
          <a href={block.url || '#'} style={getStyle(block)}>
            {block.content || 'Link Text'}
          </a>
        </div>
      );
    }

    // IMAGE
    if (block.type === 'image') {
      const style = getStyle(block);

      if (block.imageMode === 'canvas') {
        return (
          <div key={block.id} style={{ ...style, backgroundColor: '#e2e8f0', minHeight: '200px', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px dashed #cbd5e1' }}>
            <div style={{ textAlign: 'center', color: '#94a3b8' }}>
              <span style={{ fontSize: '24px', fontWeight: 'bold', display: 'block' }}>IMAGE CANVAS</span>
              <span style={{ fontSize: '14px' }}>{block.alt || 'Placeholder'}</span>
            </div>
          </div>
        );
      }

      return (
        <img 
          key={block.id} 
          src={block.url || ''} 
          alt={block.alt || ''} 
          style={style} 
          onError={(e) => {
            const target = e.target as HTMLImageElement;
            target.style.display = 'none';
            if (target.parentElement) {
              const errorMsg = document.createElement('div');
              errorMsg.innerText = "Invalid Image URL";
              errorMsg.style.color = "red";
              errorMsg.style.fontSize = "12px";
              errorMsg.style.padding = "10px";
              errorMsg.style.border = "1px solid red";
              target.parentElement.appendChild(errorMsg);
            }
          }}
        />
      );
    }

    // PARAGRAPH (Default)
    return (
      <p key={block.id} style={getStyle(block)}>
        {block.content || <span className="opacity-30">Empty Paragraph</span>}
      </p>
    );
  };

  if (blocks.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-500 p-8 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg">
        <p className="text-center">No content to preview.</p>
        <p className="text-sm">Add some blocks on the left to get started.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden min-h-[300px]">
      <div className="bg-gray-100 border-b border-gray-200 px-4 py-2 flex items-center space-x-2">
        <div className="flex space-x-1.5">
          <div className="w-3 h-3 rounded-full bg-red-400"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
          <div className="w-3 h-3 rounded-full bg-green-400"></div>
        </div>
        <span className="text-xs text-gray-500 font-medium ml-2">Preview</span>
      </div>
      <div className="p-8 bg-white" style={{ minHeight: '400px' }}>
        {blocks.map(renderBlock)}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check } from 'lucide-react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, DEFAULT_WRAPPER_STYLE, DEFAULT_LINK_STYLE, DEFAULT_IMAGE_STYLE, DEFAULT_NAV_STYLE, PREVIEW_WRAPPER_STYLE } from '../constants';

interface CodeOutputProps {
  blocks: Block[];
}

export const CodeOutput: React.FC<CodeOutputProps> = ({ blocks }) => {
  const [copied, setCopied] = useState(false);

  const cssToInline = (style: Record<string, any>) => {
    return Object.entries(style)
      .filter(([_, value]) => value !== undefined)
      .map(([key, value]) => {
        const cssKey = key.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`);
        return `${cssKey}: ${value}`;
      })
      .join('; ');
  };

  const getBlockStyle = (block: Block) => {
    let defaultStyle = {};
    if (block.type === 'heading') defaultStyle = DEFAULT_HEADING_STYLE;
    else if (block.type === 'paragraph') defaultStyle = DEFAULT_PARAGRAPH_STYLE;
    else if (block.type === 'wrapper') defaultStyle = DEFAULT_WRAPPER_STYLE;
    else if (block.type === 'nav') defaultStyle = DEFAULT_NAV_STYLE;
    else if (block.type === 'link') defaultStyle = DEFAULT_LINK_STYLE;
    else if (block.type === 'image') defaultStyle = DEFAULT_IMAGE_STYLE;

    return cssToInline({ ...defaultStyle, ...block.customStyles });
  };

  const generateBlockHtml = (block: Block, indentLevel: number = 2): string => {
    const indent = '  '.repeat(indentLevel);
    const style = getBlockStyle(block);

    // HEADING
    if (block.type === 'heading') {
      const idAttr = block.htmlId ? ` id="${block.htmlId}"` : '';
      return `${indent}<h2${idAttr} style="${style}; margin-bottom: 1rem; line-height: 1.2;">${block.content}</h2>\n`;
    }

    // WRAPPER & NAV
    if (block.type === 'wrapper' || block.type === 'nav') {
      let layoutStyles = '';
      if (block.type === 'wrapper' && block.layout === 'columns') {
        layoutStyles = ' display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; align-items: start;';
      }

      const tagName = block.type === 'nav' ? 'nav' : 'div';
      const marginBottom = block.type === 'wrapper' ? '2rem' : '1rem';

      let wrapperHtml = `${indent}<${tagName} style="${style};${layoutStyles} margin-bottom: ${marginBottom};">\n`;
      if (block.children && block.children.length > 0) {
        block.children.forEach(child => {
           if (block.type === 'wrapper' && block.layout === 'columns') {
             wrapperHtml += `${indent}  <div style="height: 100%;">\n`;
             wrapperHtml += generateBlockHtml(child, indentLevel + 2);
             wrapperHtml += `${indent}  </div>\n`;
           } else {
             wrapperHtml += generateBlockHtml(child, indentLevel + 1);
           }
        });
      }
      wrapperHtml += `${indent}</${tagName}>\n`;
      return wrapperHtml;
    }

    // LINK
    if (block.type === 'link') {
      // If inside a Nav, we usually render just the A tag or wrap it minimally. 
      // For general robustness in this simple generator, wrapping in a div is safer for block layout flows, 
      // but if the parent is a flex container (like our Nav default), just the <a> is better.
      // We'll leave it simple for now, relying on the user to style alignment if they break out of defaults.
      return `${indent}<a href="${block.url || '#'}" style="${style}">${block.content || 'Link Text'}</a>\n`;
    }

    // IMAGE
    if (block.type === 'image') {
      if (block.imageMode === 'canvas') {
        const placeholderStyle = `background-color: #e2e8f0; min-height: 200px; display: flex; align-items: center; justify-content: center; border: 2px dashed #cbd5e1; color: #94a3b8; font-family: sans-serif; font-weight: bold;`;
        return `${indent}<div style="${style}; ${placeholderStyle} margin-bottom: 1.5rem;">${block.alt || 'IMAGE CANVAS'}</div>\n`;
      }
      return `${indent}<img src="${block.url || ''}" alt="${block.alt || ''}" style="${style}; margin-bottom: 1.5rem;" />\n`;
    }

    // PARAGRAPH
    return `${indent}<p style="${style}; margin-bottom: 1.5rem; line-height: 1.6;">${block.content}</p>\n`;
  };

  const generateCode = (): string => {
    if (blocks.length === 0) return '<!-- Add blocks to generate HTML -->';

    let html = `<div style="${PREVIEW_WRAPPER_STYLE.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim()}">\n`;
    blocks.forEach(block => {
      html += generateBlockHtml(block);
    });
    html += `</div>`;
    return html;
  };

  const code = generateCode();

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="relative group rounded-lg overflow-hidden border border-gray-200 dark:border-slate-700 bg-gray-900 dark:bg-black text-gray-300">
      <div className="absolute top-2 right-2">
        <button
          onClick={handleCopy}
          className="flex items-center space-x-1.5 px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-white text-xs rounded-md transition-colors border border-gray-700"
        >
          {copied ? <Check size={14} className="text-green-400" /> : <Copy size={14} />}
          <span>{copied ? 'Copied!' : 'Copy Code'}</span>
        </button>
      </div>
      <div className="p-4 overflow-x-auto">
        <pre className="font-mono text-sm leading-relaxed whitespace-pre-wrap">
          <code className="language-html">{code}</code>
        </pre>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Plus, Code2, Layers, Layout, Moon, Sun, MonitorPlay, FileCode, Box, Image as ImageIcon, Link as LinkIcon, Type, AlignLeft, Navigation } from 'lucide-react';
import { Block, BlockType } from './types';
import { BlockEditor } from './components/BlockEditor';
import { LivePreview } from './components/LivePreview';
import { CodeOutput } from './components/CodeOutput';

const App: React.FC = () => {
  const [blocks, setBlocks] = useState<Block[]>([
    { 
      id: '0', 
      type: 'nav', 
      content: '', 
      children: [
        { id: '0a', type: 'link', content: 'About', url: '#about', customStyles: { textDecoration: 'none', color: '#1e293b' } },
        { id: '0b', type: 'link', content: 'Contact', url: '#contact', customStyles: { textDecoration: 'none', color: '#1e293b' } }
      ] 
    },
    { id: '1', type: 'heading', content: 'Welcome to the Generator' },
    { id: '2', type: 'paragraph', content: 'Create layouts with Headings, Paragraphs, Links, and Images.' },
    { 
      id: '3', 
      type: 'wrapper', 
      content: '', 
      children: [
        { id: '4', type: 'heading', content: 'About Us', htmlId: 'about', customStyles: { fontSize: '1.5rem' } },
        { id: '5', type: 'paragraph', content: 'This section has an ID, so the Nav link above works.' }
      ] 
    }
  ]);
  const [activeTab, setActiveTab] = useState<'preview' | 'code'>('preview');
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const isDark = localStorage.getItem('theme') === 'dark' || 
      (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches);
    setDarkMode(isDark);
    if (isDark) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, []);

  const toggleTheme = () => {
    setDarkMode(!darkMode);
    if (!darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  // --- Recursive Helpers ---

  const addBlockRecursive = (currentBlocks: Block[], parentId: string | null, newBlock: Block): Block[] => {
    if (parentId === null) {
      return [...currentBlocks, newBlock];
    }
    return currentBlocks.map(block => {
      if (block.id === parentId) {
        return { ...block, children: [...(block.children || []), newBlock] };
      }
      if (block.children) {
        return { ...block, children: addBlockRecursive(block.children, parentId, newBlock) };
      }
      return block;
    });
  };

  const updateBlockRecursive = (currentBlocks: Block[], id: string, updates: Partial<Block>): Block[] => {
    return currentBlocks.map(block => {
      if (block.id === id) {
        return { ...block, ...updates };
      }
      if (block.children) {
        return { ...block, children: updateBlockRecursive(block.children, id, updates) };
      }
      return block;
    });
  };

  const removeBlockRecursive = (currentBlocks: Block[], id: string): Block[] => {
    return currentBlocks
      .filter(block => block.id !== id)
      .map(block => {
        if (block.children) {
          return { ...block, children: removeBlockRecursive(block.children, id) };
        }
        return block;
      });
  };

  const moveBlockRecursive = (currentBlocks: Block[], id: string, direction: 'up' | 'down'): Block[] => {
    const index = currentBlocks.findIndex(b => b.id === id);
    if (index !== -1) {
      const newBlocks = [...currentBlocks];
      if (direction === 'up' && index > 0) {
        [newBlocks[index], newBlocks[index - 1]] = [newBlocks[index - 1], newBlocks[index]];
      } else if (direction === 'down' && index < newBlocks.length - 1) {
        [newBlocks[index], newBlocks[index + 1]] = [newBlocks[index + 1], newBlocks[index]];
      }
      return newBlocks;
    }
    return currentBlocks.map(block => {
      if (block.children) {
        return { ...block, children: moveBlockRecursive(block.children, id, direction) };
      }
      return block;
    });
  };

  // --- Handlers ---

  const addBlock = (parentId: string | null = null, type: BlockType) => {
    const newBlock: Block = {
      id: Date.now().toString() + Math.random().toString(36).substr(2, 5),
      type,
      content: '',
      children: (type === 'wrapper' || type === 'nav') ? [] : undefined,
      imageMode: type === 'image' ? 'url' : undefined
    };
    setBlocks(prev => addBlockRecursive(prev, parentId, newBlock));
  };

  const updateBlock = (id: string, updates: Partial<Block>) => {
    setBlocks(prev => updateBlockRecursive(prev, id, updates));
  };

  const removeBlock = (id: string) => {
    setBlocks(prev => removeBlockRecursive(prev, id));
  };

  const moveBlock = (id: string, direction: 'up' | 'down') => {
    setBlocks(prev => moveBlockRecursive(prev, id, direction));
  };

  // Add Button Component helper
  const AddButton = ({ type, icon: Icon, label }: { type: BlockType, icon: any, label: string }) => (
    <button
      onClick={() => addBlock(null, type)}
      className="flex flex-col items-center justify-center p-3 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-blue-500 dark:hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 rounded-lg transition-all group shadow-sm hover:shadow"
    >
      <Icon size={18} className="mb-1 text-gray-400 group-hover:text-blue-500" />
      <span className="text-xs font-medium text-gray-700 dark:text-gray-200 group-hover:text-blue-600 dark:group-hover:text-blue-400">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900 dark:selection:bg-blue-900 dark:selection:text-blue-100">
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-gray-200 dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-blue-600 rounded-lg">
              <Code2 className="text-white" size={20} />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
              HTML/CSS Generator
            </h1>
          </div>
          <div className="flex items-center space-x-4">
            <button
              onClick={toggleTheme}
              className="p-2 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg transition-colors"
            >
              {darkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
            <button className="bg-gray-900 dark:bg-white text-white dark:text-gray-900 px-4 py-2 rounded-lg text-sm font-medium hover:bg-gray-800 dark:hover:bg-gray-100 transition-colors shadow-sm">
              Export
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 lg:p-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full">

          {/* Left Column: Editor */}
          <div className="flex flex-col space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-2 text-gray-700 dark:text-gray-200">
                <Layers size={20} />
                <h2 className="text-lg font-semibold">Structure</h2>
              </div>
            </div>

            <div className="space-y-4">
              {blocks.map((block, index) => (
                <BlockEditor
                  key={block.id}
                  block={block}
                  index={index}
                  totalBlocks={blocks.length}
                  onUpdate={updateBlock}
                  onRemove={removeBlock}
                  onMove={(id, dir) => moveBlock(id, dir)}
                  onAddChild={addBlock}
                />
              ))}

              {blocks.length === 0 && (
                <div className="text-center py-12 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg bg-gray-50 dark:bg-slate-800/50">
                  <p className="text-gray-500 dark:text-gray-400 mb-2">No blocks yet</p>
                  <p className="text-sm text-gray-400 dark:text-gray-500">Add a heading, paragraph or wrapper</p>
                </div>
              )}
            </div>

            <div className="pt-4 border-t border-gray-200 dark:border-slate-800">
              <h3 className="text-sm font-medium text-gray-500 dark:text-gray-400 mb-3 uppercase tracking-wider">
                Add to Root
              </h3>
              <div className="grid grid-cols-3 sm:grid-cols-6 gap-3">
                <AddButton type="heading" icon={Type} label="Heading" />
                <AddButton type="paragraph" icon={AlignLeft} label="Paragraph" />
                <AddButton type="wrapper" icon={Box} label="Wrapper" />
                <AddButton type="nav" icon={Navigation} label="Nav" />
                <AddButton type="link" icon={LinkIcon} label="Link" />
                <AddButton type="image" icon={ImageIcon} label="Image" />
              </div>
            </div>
          </div>

          {/* Right Column: Preview/Code */}
          <div className="lg:sticky lg:top-24 h-fit flex flex-col space-y-4">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-gray-200 dark:border-slate-700 overflow-hidden">
              <div className="flex border-b border-gray-200 dark:border-slate-700">
                <button
                  onClick={() => setActiveTab('preview')}
                  className={`flex-1 flex items-center justify-center space-x-2 py-3 text-sm font-medium transition-colors ${
                    activeTab === 'preview'
                      ? 'bg-gray-50 dark:bg-slate-700/50 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600'
                      : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-50 dark:hover:bg-slate-800'
                  }`}
                >
                  <MonitorPlay size={16} />
                  <span>Live Preview</span>
                </button>
                <button
                  onClick={() => setActiveTab('code')}
                  className={`flex-1 flex items-center justify-center space-x-2 py-3 text-sm font-medium transition-colors ${
                    activeTab === 'code'
                      ? 'bg-gray-50 dark:bg-slate-700/50 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600'
                      : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-50 dark:hover:bg-slate-800'
                  }`}
                >
                  <FileCode size={16} />
                  <span>Generated HTML</span>
                </button>
              </div>

              <div className="p-4 bg-gray-50 dark:bg-slate-900/50">
                {activeTab === 'preview' ? (
                  <LivePreview blocks={blocks} />
                ) : (
                  <CodeOutput blocks={blocks} />
                )}
              </div>
            </div>

            <div className="bg-blue-50 dark:bg-blue-900/20 rounded-lg p-4 border border-blue-100 dark:border-blue-900/50">
              <div className="flex items-start space-x-3">
                <Layout className="text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" size={20} />
                <div>
                  <h4 className="text-sm font-semibold text-blue-800 dark:text-blue-300">Quick Tip</h4>
                  <p className="text-xs text-blue-700 dark:text-blue-400 mt-1">
                    To make navigation work, add a unique <strong>Anchor ID</strong> to your headings (e.g., "about"), then create a Link with the URL set to <strong>#about</strong>.
                  </p>
                </div>
              </div>
            </div>
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

export type BlockType = 'heading' | 'paragraph' | 'wrapper' | 'image' | 'link' | 'nav';

export interface StyleConfig {
  color?: string;
  fontSize?: string;
  backgroundColor?: string;
  padding?: string;
  borderRadius?: string;
  fontWeight?: string;
  textAlign?: 'left' | 'center' | 'right';
  border?: string;
  width?: string;
  height?: string;
  display?: string;
  gap?: string;
  alignItems?: string;
  textDecoration?: string;
  borderBottom?: string;
}

export interface Block {
  id: string;
  type: BlockType;
  content: string; // Heading/Para/Link text. Unused for Image (uses alt/url)
  children?: Block[]; // Nested blocks for wrappers/nav
  customStyles?: Partial<StyleConfig>;

  // New properties for Link and Image
  url?: string;       // href for Links, src for Images
  alt?: string;       // alt text for Images
  imageMode?: 'url' | 'canvas'; // 'url' for actual image, 'canvas' for skeleton

  // New properties for Wrapper
  layout?: 'stack' | 'columns'; 

  // New property for Headings (Anchor Target)
  htmlId?: string;

  // UI State
  collapsed?: boolean;
}

export interface GeneratedOutput {
  html: string;
  css: string;
}

import React from 'react';
import { Trash2, MoveUp, MoveDown, Type, AlignLeft, Box, Plus, Image as ImageIcon, Link as LinkIcon, Globe, LayoutTemplate, Columns, Rows, Navigation, Hash, ChevronDown, ChevronRight } from 'lucide-react';
import { Block, BlockType } from '../types';

interface BlockEditorProps {
  block: Block;
  index: number;
  totalBlocks: number;
  onUpdate: (id: string, updates: Partial<Block>) => void;
  onRemove: (id: string) => void;
  onMove: (id: string, direction: 'up' | 'down') => void;
  onAddChild: (parentId: string, type: BlockType) => void;
}

export const BlockEditor: React.FC<BlockEditorProps> = ({
  block,
  index,
  totalBlocks,
  onUpdate,
  onRemove,
  onMove,
  onAddChild,
}) => {
  const isWrapper = block.type === 'wrapper';
  const isNav = block.type === 'nav';
  const isContainer = isWrapper || isNav;
  const isImage = block.type === 'image';
  const isLink = block.type === 'link';
  const isHeading = block.type === 'heading';

  const isCollapsed = block.collapsed;

  const getTypeIcon = (type: BlockType) => {
    switch (type) {
      case 'heading': return <Type size={16} />;
      case 'paragraph': return <AlignLeft size={16} />;
      case 'wrapper': return <Box size={16} />;
      case 'nav': return <Navigation size={16} />;
      case 'image': return <ImageIcon size={16} />;
      case 'link': return <LinkIcon size={16} />;
    }
  };

  const getSummary = () => {
    if (isContainer) {
      const count = block.children?.length || 0;
      return `${count} item${count !== 1 ? 's' : ''}`;
    }
    if (isImage) return block.alt || block.url || 'Image block';
    if (isLink) return block.content || block.url || 'Link block';
    return block.content || `Empty ${block.type}`;
  };

  return (
    <div className={`
      relative rounded-lg border shadow-sm transition-all
      ${isContainer 
        ? isNav 
          ? 'bg-slate-50/50 dark:bg-slate-900/10 border-slate-200 dark:border-slate-800'
          : 'bg-blue-50/50 dark:bg-blue-900/10 border-blue-200 dark:border-blue-800' 
        : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 hover:shadow-md'
      }
      ${isCollapsed ? 'p-2' : 'p-4 pb-6'}
    `}>
      {/* Block Header */}
      <div className={`flex justify-between items-center ${!isCollapsed ? 'mb-3' : ''}`}>
        <div className="flex items-center space-x-2 overflow-hidden">
          {/* Collapse Toggle */}
          <button
            onClick={() => onUpdate(block.id, { collapsed: !isCollapsed })}
            className="p-1 rounded hover:bg-black/5 dark:hover:bg-white/10 text-gray-500 transition-colors"
          >
             {isCollapsed ? <ChevronRight size={16} /> : <ChevronDown size={16} />}
          </button>

          <span className={`text-xs font-mono px-2 py-1 rounded flex-shrink-0 ${
            isContainer 
              ? 'bg-blue-100 dark:bg-blue-900 text-blue-700 dark:text-blue-300' 
              : 'bg-gray-100 dark:bg-slate-700 text-gray-500 dark:text-gray-400'
          }`}>
            #{index + 1}
          </span>

          {/* Type Selector (Hidden when collapsed) */}
          {!isCollapsed && (
            <div className="flex bg-gray-100 dark:bg-slate-700 rounded-md p-1 space-x-0.5">
              {(['heading', 'paragraph', 'link', 'image', 'wrapper', 'nav'] as BlockType[]).map((t) => (
                <button
                  key={t}
                  onClick={() => onUpdate(block.id, { 
                    type: t, 
                    children: (t === 'wrapper' || t === 'nav') ? block.children || [] : undefined,
                    imageMode: t === 'image' && !block.imageMode ? 'url' : block.imageMode
                  })}
                  className={`p-1.5 rounded transition-all ${
                    block.type === t 
                      ? 'bg-white dark:bg-slate-600 shadow-sm text-blue-600 dark:text-blue-400 scale-105' 
                      : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-300'
                  }`}
                  title={t.charAt(0).toUpperCase() + t.slice(1)}
                >
                  {getTypeIcon(t)}
                </button>
              ))}
            </div>
          )}

          {/* Collapsed View Summary */}
          {isCollapsed && (
             <div className="flex items-center space-x-2 text-sm text-gray-500 dark:text-gray-400">
               <span className="flex items-center space-x-1 font-medium text-gray-700 dark:text-gray-200">
                 {getTypeIcon(block.type)}
                 <span className="capitalize">{block.type}</span>
               </span>
               <span className="text-gray-300 dark:text-gray-600">|</span>
               <span className="truncate max-w-[200px] italic">{getSummary()}</span>
