  border?: string;
  width?: string;
  height?: string;
  display?: string;
  gap?: string;
  alignItems?: string;
  textDecoration?: string;
  borderBottom?: string;
  overflowWrap?: string;
  wordBreak?: string;
  maxWidth?: string;
}

