import React from 'react';
import { Trash2, MoveUp, MoveDown, Type, AlignLeft, Box, Plus, Image as ImageIcon, Link as LinkIcon, Globe, LayoutTemplate, Columns, Rows, Navigation, Hash, ChevronDown, ChevronRight, Palette } from 'lucide-react';
import { Block, BlockType } from '../types';
import { WRAPPER_PALETTE } from '../constants';

interface BlockEditorProps {
  block: Block;
  index: number;
  totalBlocks: number;
  onUpdate: (id: string, updates: Partial<Block>) => void;
  onRemove: (id: string) => void;
  onMove: (id: string, direction: 'up' | 'down') => void;
  onAddChild: (parentId: string, type: BlockType) => void;
  wrapperDepth?: number;
}

export const BlockEditor: React.FC<BlockEditorProps> = ({
  block,
  index,
  totalBlocks,
  onUpdate,
  onRemove,
  onMove,
  onAddChild,
  wrapperDepth = 0,
}) => {
  const isWrapper = block.type === 'wrapper';
  const isNav = block.type === 'nav';
  const isContainer = isWrapper || isNav;
  const isImage = block.type === 'image';
  const isLink = block.type === 'link';
  const isHeading = block.type === 'heading';

  const isCollapsed = block.collapsed;
  const isNestedWrapper = isWrapper && wrapperDepth > 0;

  const getTypeIcon = (type: BlockType) => {
    switch (type) {
      case 'heading': return <Type size={16} />;
      case 'paragraph': return <AlignLeft size={16} />;
      case 'wrapper': return <Box size={16} />;
      case 'nav': return <Navigation size={16} />;
      case 'image': return <ImageIcon size={16} />;
      case 'link': return <LinkIcon size={16} />;
    }
  };

  const getSummary = () => {
    if (isContainer) {
      const count = block.children?.length || 0;
      return `${count} item${count !== 1 ? 's' : ''}`;
    }
    if (isHeading) {
      const level = block.headingLevel || 2;
      return `H${level}: ${block.content || 'Empty'}`;
    }
    if (isImage) return block.alt || block.url || 'Image block';
    if (isLink) return block.content || block.url || 'Link block';
    return block.content || `Empty ${block.type}`;
  };

  // Determine allowed types for switching
  const allowedSwitchTypes: BlockType[] = ['heading', 'paragraph', 'link', 'image', 'wrapper', 'nav'];

  // Determine allowed types for adding children
  const allowedChildTypes: BlockType[] = ['heading', 'paragraph', 'image', 'link'];
  // Only allow adding a wrapper if we are not already deep in a wrapper
  if (wrapperDepth < 1) {
    allowedChildTypes.push('wrapper');
  }

  return (
    <div className={`
      relative rounded-lg border shadow-sm transition-all
      ${isContainer 
        ? isNav 
          ? 'bg-slate-50/50 dark:bg-slate-900/10 border-slate-200 dark:border-slate-800'
          : isNestedWrapper 
            ? 'bg-white dark:bg-slate-800 border-blue-300 dark:border-blue-700 shadow-md' // Distinct style for nested
            : 'bg-blue-50/50 dark:bg-blue-900/10 border-blue-200 dark:border-blue-800' 
        : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 hover:shadow-md'
      }
      ${isCollapsed ? 'p-2' : 'p-4 pb-6'}
    `}>
      {/* Block Header */}
      <div className={`flex justify-between items-center ${!isCollapsed ? 'mb-3' : ''}`}>
        <div className="flex items-center space-x-2 overflow-hidden">
          {/* Collapse Toggle */}
          <button
            onClick={() => onUpdate(block.id, { collapsed: !isCollapsed })}
            className="p-1 rounded hover:bg-black/5 dark:hover:bg-white/10 text-gray-500 transition-colors"
          >
             {isCollapsed ? <ChevronRight size={16} /> : <ChevronDown size={16} />}
          </button>

          <span className={`text-xs font-mono px-2 py-1 rounded flex-shrink-0 ${
            isContainer 
              ? 'bg-blue-100 dark:bg-blue-900 text-blue-700 dark:text-blue-300' 
              : 'bg-gray-100 dark:bg-slate-700 text-gray-500 dark:text-gray-400'
          }`}>
            #{index + 1}
          </span>

          {/* Type Selector (Hidden when collapsed) */}
          {!isCollapsed && (
            <div className="flex bg-gray-100 dark:bg-slate-700 rounded-md p-1 space-x-0.5">
              {allowedSwitchTypes.map((t) => {
                // Disable wrapper option if depth is too high (prevent turning a deep child into a wrapper)
                const isDisabled = t === 'wrapper' && wrapperDepth >= 2;
                if (isDisabled) return null;

                return (
                  <button
                    key={t}
                    onClick={() => onUpdate(block.id, { 
                      type: t, 
                      children: (t === 'wrapper' || t === 'nav') ? block.children || [] : undefined,
                      imageMode: t === 'image' && !block.imageMode ? 'url' : block.imageMode,
                      headingLevel: t === 'heading' ? 2 : undefined
                    })}
                    className={`p-1.5 rounded transition-all ${
                      block.type === t 
                        ? 'bg-white dark:bg-slate-600 shadow-sm text-blue-600 dark:text-blue-400 scale-105' 
                        : 'text-gray-400 hover:text-gray-600 dark:hover:text-gray-300'
                    }`}
                    title={t.charAt(0).toUpperCase() + t.slice(1)}
                  >
                    {getTypeIcon(t)}
                  </button>
                );
              })}
            </div>
          )}

          {/* Collapsed View Summary */}
          {isCollapsed && (
             <div className="flex items-center space-x-2 text-sm text-gray-500 dark:text-gray-400">
               <span className="flex items-center space-x-1 font-medium text-gray-700 dark:text-gray-200">
                 {getTypeIcon(block.type)}
                 <span className="capitalize">{block.type}</span>
               </span>
               <span className="text-gray-300 dark:text-gray-600">|</span>
               <span className="truncate max-w-[200px] italic">{getSummary()}</span>
             </div>
          )}

          {!isCollapsed && (
            <span className="text-sm font-medium text-gray-700 dark:text-gray-200 capitalize hidden sm:inline-block">
              {block.type}
            </span>
          )}
        </div>

        {/* Action Buttons */}
        <div className="flex items-center space-x-1 flex-shrink-0 ml-2">
          <button
            onClick={() => onMove(block.id, 'up')}
            disabled={index === 0}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-30 transition-colors"
          >
            <MoveUp size={16} />
          </button>
          <button
            onClick={() => onMove(block.id, 'down')}
            disabled={index === totalBlocks - 1}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-30 transition-colors"
          >
            <MoveDown size={16} />
          </button>
          <div className="w-px h-4 bg-gray-200 dark:bg-slate-700 mx-1"></div>
          <button
            onClick={() => onRemove(block.id)}
            className="p-1.5 text-gray-400 hover:text-red-500 transition-colors"
          >
            <Trash2 size={16} />
          </button>
        </div>
      </div>

      {/* Editor Content (Hidden when collapsed) */}
      {!isCollapsed && (
      <div className="space-y-3">

        {/* HEADING EXTRAS (Level + ID) */}
        {isHeading && (
          <div className="space-y-3 mb-2">
            <div className="flex items-center justify-between gap-4">
              {/* Level Selector */}
              <div className="flex bg-gray-100 dark:bg-slate-700 p-1 rounded-md flex-shrink-0">
                  {[2, 3, 4].map(level => (
                      <button
                          key={level}
                          onClick={() => onUpdate(block.id, { headingLevel: level as 2|3|4 })}
                          className={`px-3 py-1 text-xs font-bold rounded transition-all ${
                              (block.headingLevel || 2) === level 
                              ? 'bg-white dark:bg-slate-600 shadow-sm text-black dark:text-white' 
                              : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200'
                          }`}
                      >
                          H{level}
                      </button>
                  ))}
              </div>

              {/* ID Input */}
              <div className="relative flex-1">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                  <Hash size={14} />
                </div>
                <input
                  type="text"
                  value={block.htmlId || ''}
                  onChange={(e) => onUpdate(block.id, { htmlId: e.target.value })}
                  placeholder="Anchor ID (e.g. 'about')"
                  className="w-full pl-9 p-1.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-xs font-mono text-gray-700 dark:text-gray-200"
                />
              </div>
            </div>
            <div className="text-[10px] text-gray-400 text-right leading-tight">
              Link with URL #ID
            </div>
          </div>
        )}

        {/* IMAGE EDITOR */}
        {isImage && (
          <div className="space-y-3">
            <div className="flex space-x-2 bg-gray-50 dark:bg-slate-900/50 p-1 rounded-lg w-fit border border-gray-200 dark:border-slate-700">
              <button
                onClick={() => onUpdate(block.id, { imageMode: 'url' })}
                className={`flex items-center space-x-2 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                  block.imageMode === 'url' || !block.imageMode
                    ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' 
                    : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                }`}
              >
                <Globe size={14} />
                <span>HTTPS Link</span>
              </button>
              <button
                onClick={() => onUpdate(block.id, { imageMode: 'canvas' })}
                className={`flex items-center space-x-2 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                  block.imageMode === 'canvas'
                    ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' 
                    : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                }`}
              >
                <LayoutTemplate size={14} />
                <span>Canvas Skeleton</span>
              </button>
            </div>

            {block.imageMode === 'url' || !block.imageMode ? (
              <input
                type="text"
                value={block.url || ''}
                onChange={(e) => onUpdate(block.id, { url: e.target.value })}
                placeholder="https://example.com/image.jpg"
                className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm font-mono text-gray-700 dark:text-gray-200"
              />
            ) : (
              <div className="text-xs text-gray-500 dark:text-gray-400 italic px-1">
                A placeholder box will be generated. No URL needed.
              </div>
            )}

            <input
              type="text"
              value={block.alt || ''}
              onChange={(e) => onUpdate(block.id, { alt: e.target.value })}
              placeholder="Alt text (description for accessibility)"
              className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm text-gray-700 dark:text-gray-200"
            />
          </div>
        )}

        {/* LINK EDITOR */}
        {isLink && (
          <div className="space-y-3">
             <input
              type="text"
              value={block.content}
              onChange={(e) => onUpdate(block.id, { content: e.target.value })}
              placeholder="Link Text (e.g. 'Click Here')"
              className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm font-medium text-gray-700 dark:text-gray-200"
            />
            <input
              type="text"
              value={block.url || ''}
              onChange={(e) => onUpdate(block.id, { url: e.target.value })}
              placeholder="URL or #anchor (e.g. #about)"
              className="w-full p-2.5 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm font-mono text-gray-700 dark:text-gray-200"
            />
          </div>
        )}

        {/* CONTAINER EDITOR (WRAPPER / NAV) */}
        {isContainer && (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div className={`text-xs font-medium px-1 ${isNav ? 'text-slate-600 dark:text-slate-400' : 'text-blue-600 dark:text-blue-400'}`}>
                {isNav ? 'Navigation Links' : isNestedWrapper ? 'Nested Wrapper' : 'Wrapper Layout'}
              </div>
            </div>

            {/* Layout Toggle for Wrapper only */}
            {isWrapper && (
              <div className="flex flex-col space-y-4 bg-white dark:bg-slate-800 p-2 rounded-lg border border-gray-200 dark:border-slate-700 w-full sm:w-fit">
                <div className="flex items-center space-x-2">
                  <span className="text-[10px] uppercase tracking-wider text-gray-400 font-bold w-12">Layout</span>
                  <div className="flex space-x-1">
                    <button
                      onClick={() => onUpdate(block.id, { layout: 'stack' })}
                      className={`flex items-center space-x-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                        block.layout !== 'columns'
                          ? 'bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 shadow-sm' 
                          : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                      }`}
                    >
                      <Rows size={14} />
                      <span>Stack</span>
                    </button>
                    <button
                      onClick={() => onUpdate(block.id, { layout: 'columns' })}
                      className={`flex items-center space-x-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                        block.layout === 'columns'
                          ? 'bg-blue-50 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400 shadow-sm' 
                          : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
                      }`}
                    >
                      <Columns size={14} />
                      <span>2 Columns</span>
                    </button>
                  </div>
                </div>

                <div className="flex items-center space-x-2 border-t border-gray-100 dark:border-slate-700 pt-2 mt-2">
                  <span className="text-[10px] uppercase tracking-wider text-gray-400 font-bold w-12">Color</span>
                  <div className="flex flex-wrap gap-2">
                    {WRAPPER_PALETTE.map(theme => (
                      <button 
                        key={theme.name}
                        onClick={() => onUpdate(block.id, { 
                          customStyles: { 
                            ...block.customStyles, 
                            backgroundColor: theme.bg, 
                            border: `1px solid ${theme.border}` 
                          } 
                        })}
                        className={`w-6 h-6 rounded-full border shadow-sm transition-transform hover:scale-110 ${theme.dotClass} ${
                          block.customStyles?.backgroundColor === theme.bg ? 'ring-2 ring-offset-2 ring-blue-500 dark:ring-offset-slate-800' : ''
                        }`}
                        title={theme.name}
                      />
                    ))}
                  </div>
                </div>
              </div>
            )}

            <div className={`space-y-4 pl-4 border-l-2 ${isNav ? 'border-slate-200 dark:border-slate-700' : 'border-blue-200 dark:border-blue-800'}`}>
              {block.children && block.children.length > 0 ? (
                block.children.map((childBlock, childIndex) => (
                  <BlockEditor
                    key={childBlock.id}
                    block={childBlock}
                    index={childIndex}
                    totalBlocks={block.children!.length}
                    onUpdate={onUpdate}
                    onRemove={onRemove}
                    onMove={onMove}
                    onAddChild={onAddChild}
                    // Increment depth for recursive children
                    wrapperDepth={isWrapper ? wrapperDepth + 1 : wrapperDepth}
                  />
                ))
              ) : (
                <div className={`p-4 border-2 border-dashed rounded-lg text-center text-sm ${isNav ? 'border-slate-200 dark:border-slate-800 text-slate-400' : 'border-blue-200 dark:border-blue-900 text-blue-400'}`}>
                  {isNav ? 'Add links to your navigation bar' : 'Wrapper is empty'}
                </div>
              )}
            </div>

            <div className="flex flex-wrap gap-2 mt-2">
              {isNav ? (
                <button
                  onClick={() => onAddChild(block.id, 'link')}
                  className="flex items-center space-x-1 py-1.5 px-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 text-xs rounded hover:bg-slate-50 dark:hover:bg-slate-800/80 transition-colors shadow-sm"
                >
                  <Plus size={12} />
                  <span>Add Link</span>
                </button>
              ) : (
                allowedChildTypes.map(type => (
                   <button
                   key={type}
                   onClick={() => onAddChild(block.id, type)}
                   className="flex items-center space-x-1 py-1.5 px-3 bg-white dark:bg-slate-800 border border-blue-200 dark:border-blue-800 text-blue-600 dark:text-blue-400 text-xs rounded hover:bg-blue-50 dark:hover:bg-blue-900/30 transition-colors"
                 >
                   <Plus size={12} />
                   <span className="capitalize">{type}</span>
                 </button>
                ))
              )}
            </div>
          </div>
        )}

        {/* TEXT EDITOR (Heading/Paragraph) */}
        {!isContainer && !isImage && !isLink && (
          <textarea
            value={block.content}
            onChange={(e) => onUpdate(block.id, { content: e.target.value })}
            placeholder={`Enter your ${block.type} text here...`}
            className="w-full p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all min-h-[100px] text-gray-800 dark:text-gray-100 placeholder-gray-400 dark:placeholder-slate-500 resize-y text-sm"
          />
        )}
      </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Plus, Code2, Layers, Layout, Moon, Sun, MonitorPlay, FileCode, Box, Image as ImageIcon, Link as LinkIcon, Type, AlignLeft, Navigation } from 'lucide-react';
import { Block, BlockType } from './types';
import { BlockEditor } from './components/BlockEditor';
import { LivePreview } from './components/LivePreview';
import { CodeOutput } from './components/CodeOutput';
import { WRAPPER_PALETTE } from './constants';

const App: React.FC = () => {
  const [blocks, setBlocks] = useState<Block[]>([
    { 
      id: '0', 
      type: 'nav', 
      content: '', 
      children: [
        { id: '0a', type: 'link', content: 'About', url: '#about', customStyles: { textDecoration: 'none', color: '#1e293b' } },
        { id: '0b', type: 'link', content: 'Contact', url: '#contact', customStyles: { textDecoration: 'none', color: '#1e293b' } }
      ] 
    },
    { id: '1', type: 'heading', headingLevel: 2, content: 'Welcome to the Generator' },
    { id: '2', type: 'paragraph', content: 'Create layouts with Headings, Paragraphs, Links, and Images.' },
    { 
      id: '3', 
      type: 'wrapper', 
      content: '', 
      // Set default color to Blue (palette index 0) for the demo wrapper
      customStyles: {
        backgroundColor: WRAPPER_PALETTE[0].bg,
        border: `1px solid ${WRAPPER_PALETTE[0].border}`
      },
      children: [
        { id: '4', type: 'heading', headingLevel: 3, content: 'About Us', htmlId: 'about' },
        { id: '5', type: 'paragraph', content: 'This section has an ID, so the Nav link above works.' }
      ] 
    }
  ]);
  const [activeTab, setActiveTab] = useState<'preview' | 'code'>('preview');
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const isDark = localStorage.getItem('theme') === 'dark' || 
      (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches);
    setDarkMode(isDark);
    if (isDark) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, []);

  const toggleTheme = () => {
    setDarkMode(!darkMode);
    if (!darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  // --- Recursive Helpers ---

  const addBlockRecursive = (currentBlocks: Block[], parentId: string | null, newBlock: Block): Block[] => {
    if (parentId === null) {
      return [...currentBlocks, newBlock];
    }
    return currentBlocks.map(block => {
      if (block.id === parentId) {
        return { ...block, children: [...(block.children || []), newBlock] };
      }
      if (block.children) {
        return { ...block, children: addBlockRecursive(block.children, parentId, newBlock) };
      }
      return block;
    });
  };

  const updateBlockRecursive = (currentBlocks: Block[], id: string, updates: Partial<Block>): Block[] => {
    return currentBlocks.map(block => {
      if (block.id === id) {
        return { ...block, ...updates };
      }
      if (block.children) {
        return { ...block, children: updateBlockRecursive(block.children, id, updates) };
      }
      return block;
    });
  };

  const removeBlockRecursive = (currentBlocks: Block[], id: string): Block[] => {
    return currentBlocks
      .filter(block => block.id !== id)
      .map(block => {
        if (block.children) {
          return { ...block, children: removeBlockRecursive(block.children, id) };
        }
        return block;
      });
  };

  const moveBlockRecursive = (currentBlocks: Block[], id: string, direction: 'up' | 'down'): Block[] => {
    const index = currentBlocks.findIndex(b => b.id === id);
    if (index !== -1) {
      const newBlocks = [...currentBlocks];
      if (direction === 'up' && index > 0) {
        [newBlocks[index], newBlocks[index - 1]] = [newBlocks[index - 1], newBlocks[index]];
      } else if (direction === 'down' && index < newBlocks.length - 1) {
        [newBlocks[index], newBlocks[index + 1]] = [newBlocks[index + 1], newBlocks[index]];
      }
      return newBlocks;
    }
    return currentBlocks.map(block => {
      if (block.children) {
        return { ...block, children: moveBlockRecursive(block.children, id, direction) };
      }
      return block;
    });
  };

  // --- Handlers ---

  const addBlock = (parentId: string | null = null, type: BlockType) => {
    let customStyles = {};

    if (type === 'wrapper') {
      // Pick a random color from the palette
      const randomTheme = WRAPPER_PALETTE[Math.floor(Math.random() * WRAPPER_PALETTE.length)];
      customStyles = {
        backgroundColor: randomTheme.bg,
        border: `1px solid ${randomTheme.border}`
      };
    }

    const newBlock: Block = {
      id: Date.now().toString() + Math.random().toString(36).substr(2, 5),
      type,
      headingLevel: type === 'heading' ? 2 : undefined,
      content: '',
      children: (type === 'wrapper' || type === 'nav') ? [] : undefined,
      imageMode: type === 'image' ? 'url' : undefined,
      customStyles
    };
    setBlocks(prev => addBlockRecursive(prev, parentId, newBlock));
  };

  const updateBlock = (id: string, updates: Partial<Block>) => {
    setBlocks(prev => updateBlockRecursive(prev, id, updates));
  };

  const removeBlock = (id: string) => {
    setBlocks(prev => removeBlockRecursive(prev, id));
  };

  const moveBlock = (id: string, direction: 'up' | 'down') => {
    setBlocks(prev => moveBlockRecursive(prev, id, direction));
  };

  // Add Button Component helper
  const AddButton = ({ type, icon: Icon, label }: { type: BlockType, icon: any, label: string }) => (
    <button
      onClick={() => addBlock(null, type)}
      className="flex flex-col items-center justify-center p-3 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-blue-500 dark:hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 rounded-lg transition-all group shadow-sm hover:shadow"
    >
      <Icon size={18} className="mb-1 text-gray-400 group-hover:text-blue-500" />
      <span className="text-xs font-medium text-gray-700 dark:text-gray-200 group-hover:text-blue-600 dark:group-hover:text-blue-400">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900 dark:selection:bg-blue-900 dark:selection:text-blue-100">
      <header className="sticky top-0 z-50 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-gray-200 dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-blue-600 rounded-lg">
              <Code2 className="text-white" size={20} />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
              HTML/CSS Generator
            </h1>
          </div>
          <div className="flex items-center space-x-4">
            <button
              onClick={toggleTheme}
              className="p-2 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg transition-colors"
            >
              {darkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
            <button className="bg-gray-900 dark:bg-white text-white dark:text-gray-900 px-4 py-2 rounded-lg text-sm font-medium hover:bg-gray-800 dark:hover:bg-gray-100 transition-colors shadow-sm">
              Export
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 lg:p-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full">

          {/* Left Column: Editor */}
          <div className="flex flex-col space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-2 text-gray-700 dark:text-gray-200">
                <Layers size={20} />
                <h2 className="text-lg font-semibold">Structure</h2>
              </div>
            </div>

            <div className="space-y-4">
              {blocks.map((block, index) => (
                <BlockEditor
                  key={block.id}
                  block={block}
                  index={index}
                  totalBlocks={blocks.length}
                  onUpdate={updateBlock}
                  onRemove={removeBlock}
                  onMove={(id, dir) => moveBlock(id, dir)}
                  onAddChild={addBlock}
                />
              ))}

              {blocks.length === 0 && (
                <div className="text-center py-12 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg bg-gray-50 dark:bg-slate-800/50">
                  <p className="text-gray-500 dark:text-gray-400 mb-2">No blocks yet</p>
                  <p className="text-sm text-gray-400 dark:text-gray-500">Add a heading, paragraph or wrapper</p>
                </div>
              )}
            </div>

            <div className="pt-4 border-t border-gray-200 dark:border-slate-800">
              <h3 className="text-sm font-medium text-gray-500 dark:text-gray-400 mb-3 uppercase tracking-wider">
                Add to Root
              </h3>
              <div className="grid grid-cols-3 sm:grid-cols-6 gap-3">
                <AddButton type="heading" icon={Type} label="Heading" />
                <AddButton type="paragraph" icon={AlignLeft} label="Paragraph" />
                <AddButton type="wrapper" icon={Box} label="Wrapper" />
                <AddButton type="nav" icon={Navigation} label="Nav" />
                <AddButton type="link" icon={LinkIcon} label="Link" />
                <AddButton type="image" icon={ImageIcon} label="Image" />
              </div>
            </div>
          </div>

          {/* Right Column: Preview/Code */}
          <div className="lg:sticky lg:top-24 h-fit flex flex-col space-y-4">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-gray-200 dark:border-slate-700 overflow-hidden">
              <div className="flex border-b border-gray-200 dark:border-slate-700">
                <button
                  onClick={() => setActiveTab('preview')}
                  className={`flex-1 flex items-center justify-center space-x-2 py-3 text-sm font-medium transition-colors ${
                    activeTab === 'preview'
                      ? 'bg-gray-50 dark:bg-slate-700/50 text-blue-600 dark:text-blue-400 border-b-2 border-blue-600'
                      : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-50 dark:hover:bg-slate-800'
                  }`}
                >
                  <MonitorPlay size={16} />
                  <span>Live Preview</span>
                </button>
                <button
                  onClick={() => setActiveTab('code')}
