import React from 'react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, DEFAULT_WRAPPER_STYLE, DEFAULT_LINK_STYLE, DEFAULT_IMAGE_STYLE, DEFAULT_NAV_STYLE, HEADING_SIZES } from '../constants';

interface LivePreviewProps {
  blocks: Block[];
}

export const LivePreview: React.FC<LivePreviewProps> = ({ blocks }) => {
  const getStyle = (block: Block): React.CSSProperties => {
    let defaultStyle = {};
    if (block.type === 'heading') defaultStyle = DEFAULT_HEADING_STYLE;
    else if (block.type === 'paragraph') defaultStyle = DEFAULT_PARAGRAPH_STYLE;
    else if (block.type === 'wrapper') defaultStyle = DEFAULT_WRAPPER_STYLE;
    else if (block.type === 'nav') defaultStyle = DEFAULT_NAV_STYLE;
    else if (block.type === 'link') defaultStyle = DEFAULT_LINK_STYLE;
    else if (block.type === 'image') defaultStyle = DEFAULT_IMAGE_STYLE;

    const combined = { ...defaultStyle, ...block.customStyles };

    // Apply heading size
    if (block.type === 'heading') {
      const level = block.headingLevel || 2;
      combined.fontSize = HEADING_SIZES[level as keyof typeof HEADING_SIZES];
    }

    // Wrapper specific layout styles
    const layoutStyles: React.CSSProperties = {};
    if (block.type === 'wrapper' && block.layout === 'columns') {
      layoutStyles.display = 'grid';
      layoutStyles.gridTemplateColumns = '1fr 1fr';
      layoutStyles.gap = '1.5rem';
      layoutStyles.alignItems = 'start';
    }

    const baseStyle: React.CSSProperties = {
      ...(combined as React.CSSProperties),
      ...layoutStyles,
      marginBottom: (block.type === 'heading' || block.type === 'nav') ? '1rem' : block.type === 'wrapper' ? '2rem' : '1.5rem',
      lineHeight: block.type === 'heading' ? '1.2' : '1.6',
      boxSizing: 'border-box',
    };

    return baseStyle;
  };

  const renderBlock = (block: Block) => {
    // HEADING
    if (block.type === 'heading') {
      const level = block.headingLevel || 2;
      const Tag = `h${level}` as React.ElementType;
      return (
        <Tag key={block.id} id={block.htmlId} style={getStyle(block)}>
          {block.content || <span className="opacity-30">Empty Heading</span>}
        </Tag>
      );
    }

    // WRAPPER & NAV
    if (block.type === 'wrapper' || block.type === 'nav') {
      const style = getStyle(block);
      const ContainerTag = (block.type === 'nav' ? 'nav' : 'div') as React.ElementType;

      return (
        <ContainerTag key={block.id} style={style}>
          {block.children && block.children.length > 0 ? (
            block.children.map((child) => (
              <div key={child.id} style={block.layout === 'columns' ? { height: '100%' } : undefined}>
                 {renderBlock(child)}
              </div>
            ))
          ) : (
            <div style={{ gridColumn: '1 / -1', width: '100%' }} className={`text-sm text-center italic border-2 border-dashed p-4 rounded ${block.type === 'nav' ? 'border-slate-300/50 text-slate-400' : 'border-blue-200 text-blue-400'}`}>
              {block.type === 'nav' ? 'Empty Nav Bar' : 'Empty Wrapper'}
            </div>
          )}
        </ContainerTag>
      );
    }

    // LINK
    if (block.type === 'link') {
      return (
        <div key={block.id} style={{ marginBottom: '0' /* links in navs shouldn't have bottom margin usually, but let's keep it safe */ }}>
          <a href={block.url || '#'} style={getStyle(block)}>
            {block.content || 'Link Text'}
          </a>
        </div>
      );
    }

    // IMAGE
    if (block.type === 'image') {
      const style = getStyle(block);

      if (block.imageMode === 'canvas') {
        return (
          <div key={block.id} style={{ ...style, backgroundColor: '#e2e8f0', minHeight: '200px', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px dashed #cbd5e1' }}>
            <div style={{ textAlign: 'center', color: '#94a3b8' }}>
              <span style={{ fontSize: '24px', fontWeight: 'bold', display: 'block' }}>IMAGE CANVAS</span>
              <span style={{ fontSize: '14px' }}>{block.alt || 'Placeholder'}</span>
            </div>
          </div>
        );
      }

      return (
        <img 
          key={block.id} 
          src={block.url || ''} 
          alt={block.alt || ''} 
          style={style} 
          onError={(e) => {
            const target = e.target as HTMLImageElement;
            target.style.display = 'none';
            if (target.parentElement) {
              const errorMsg = document.createElement('div');
              errorMsg.innerText = "Invalid Image URL";
              errorMsg.style.color = "red";
              errorMsg.style.fontSize = "12px";
              errorMsg.style.padding = "10px";
              errorMsg.style.border = "1px solid red";
              target.parentElement.appendChild(errorMsg);
            }
          }}
        />
      );
    }

    // PARAGRAPH (Default)
    return (
      <p key={block.id} style={getStyle(block)}>
        {block.content || <span className="opacity-30">Empty Paragraph</span>}
      </p>
    );
  };

  if (blocks.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-500 p-8 border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-lg">
        <p className="text-center">No content to preview.</p>
        <p className="text-sm">Add some blocks on the left to get started.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden min-h-[300px]">
      <div className="bg-gray-100 border-b border-gray-200 px-4 py-2 flex items-center space-x-2">
        <div className="flex space-x-1.5">
          <div className="w-3 h-3 rounded-full bg-red-400"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
          <div className="w-3 h-3 rounded-full bg-green-400"></div>
        </div>
        <span className="text-xs text-gray-500 font-medium ml-2">Preview</span>
      </div>
      <div className="p-8 bg-white" style={{ minHeight: '400px' }}>
        {blocks.map(renderBlock)}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Copy, Check } from 'lucide-react';
import { Block } from '../types';
import { DEFAULT_HEADING_STYLE, DEFAULT_PARAGRAPH_STYLE, DEFAULT_WRAPPER_STYLE, DEFAULT_LINK_STYLE, DEFAULT_IMAGE_STYLE, DEFAULT_NAV_STYLE, PREVIEW_WRAPPER_STYLE, HEADING_SIZES } from '../constants';

interface CodeOutputProps {
  blocks: Block[];
}

export const CodeOutput: React.FC<CodeOutputProps> = ({ blocks }) => {
  const [copied, setCopied] = useState(false);

  const cssToInline = (style: Record<string, any>) => {
    return Object.entries(style)
      .filter(([_, value]) => value !== undefined)
      .map(([key, value]) => {
        const cssKey = key.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`);
        return `${cssKey}: ${value}`;
      })
      .join('; ');
  };

  const getBlockStyle = (block: Block) => {
    let defaultStyle = {};
    if (block.type === 'heading') defaultStyle = DEFAULT_HEADING_STYLE;
    else if (block.type === 'paragraph') defaultStyle = DEFAULT_PARAGRAPH_STYLE;
    else if (block.type === 'wrapper') defaultStyle = DEFAULT_WRAPPER_STYLE;
    else if (block.type === 'nav') defaultStyle = DEFAULT_NAV_STYLE;
    else if (block.type === 'link') defaultStyle = DEFAULT_LINK_STYLE;
    else if (block.type === 'image') defaultStyle = DEFAULT_IMAGE_STYLE;

    const combined = { ...defaultStyle, ...block.customStyles };

    // Explicitly set heading size
    if (block.type === 'heading') {
        const level = block.headingLevel || 2;
        combined.fontSize = HEADING_SIZES[level as keyof typeof HEADING_SIZES];
    }

    return cssToInline(combined);
  };

  const generateBlockHtml = (block: Block, indentLevel: number = 2): string => {
    const indent = '  '.repeat(indentLevel);
    const style = getBlockStyle(block);

    // HEADING
    if (block.type === 'heading') {
      const idAttr = block.htmlId ? ` id="${block.htmlId}"` : '';
      const level = block.headingLevel || 2;
      return `${indent}<h${level}${idAttr} style="${style}; margin-bottom: 1rem; line-height: 1.2;">${block.content}</h${level}>\n`;
    }

    // WRAPPER & NAV
    if (block.type === 'wrapper' || block.type === 'nav') {
      let layoutStyles = '';
      if (block.type === 'wrapper' && block.layout === 'columns') {
        layoutStyles = ' display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; align-items: start;';
      }

      const tagName = block.type === 'nav' ? 'nav' : 'div';
      const marginBottom = block.type === 'wrapper' ? '2rem' : '1rem';

      let wrapperHtml = `${indent}<${tagName} style="${style};${layoutStyles} margin-bottom: ${marginBottom};">\n`;
      if (block.children && block.children.length > 0) {
        block.children.forEach(child => {
           if (block.type === 'wrapper' && block.layout === 'columns') {
             // min-width: 0 prevents grid item blowout from long content
             wrapperHtml += `${indent}  <div style="height: 100%; min-width: 0;">\n`;
             wrapperHtml += generateBlockHtml(child, indentLevel + 2);
             wrapperHtml += `${indent}  </div>\n`;
           } else {
             wrapperHtml += generateBlockHtml(child, indentLevel + 1);
           }
        });
      }
      wrapperHtml += `${indent}</${tagName}>\n`;
      return wrapperHtml;
    }

    // LINK
    if (block.type === 'link') {
      // If inside a Nav, we usually render just the A tag or wrap it minimally. 
      // For general robustness in this simple generator, wrapping in a div is safer for block layout flows, 
      // but if the parent is a flex container (like our Nav default), just the <a> is better.
      // We'll leave it simple for now, relying on the user to style alignment if they break out of defaults.
      return `${indent}<a href="${block.url || '#'}" style="${style}">${block.content || 'Link Text'}</a>\n`;
    }

    // IMAGE
    if (block.type === 'image') {
      if (block.imageMode === 'canvas') {
        const placeholderStyle = `background-color: #e2e8f0; min-height: 200px; display: flex; align-items: center; justify-content: center; border: 2px dashed #cbd5e1; color: #94a3b8; font-family: sans-serif; font-weight: bold;`;
        return `${indent}<div style="${style}; ${placeholderStyle} margin-bottom: 1.5rem;">${block.alt || 'IMAGE CANVAS'}</div>\n`;
      }
      return `${indent}<img src="${block.url || ''}" alt="${block.alt || ''}" style="${style}; margin-bottom: 1.5rem;" />\n`;
    }

    // PARAGRAPH
    return `${indent}<p style="${style}; margin-bottom: 1.5rem; line-height: 1.6;">${block.content}</p>\n`;
  };

  const generateCode = (): string => {
    if (blocks.length === 0) return '<!-- Add blocks to generate HTML -->';

    let html = `<div style="${PREVIEW_WRAPPER_STYLE.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim()}">\n`;
    blocks.forEach(block => {
      html += generateBlockHtml(block);
    });
    html += `</div>`;
    return html;
  };

  const code = generateCode();

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="relative group rounded-lg overflow-hidden border border-gray-200 dark:border-slate-700 bg-gray-900 dark:bg-black text-gray-300">
      <div className="absolute top-2 right-2">
        <button
          onClick={handleCopy}
          className="flex items-center space-x-1.5 px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-white text-xs rounded-md transition-colors border border-gray-700"
        >
          {copied ? <Check size={14} className="text-green-400" /> : <Copy size={14} />}
          <span>{copied ? 'Copied!' : 'Copy Code'}</span>
        </button>
      </div>
      <div className="p-4 overflow-x-auto">
        <pre className="font-mono text-sm leading-relaxed whitespace-pre-wrap break-all">
          <code className="language-html">{code}</code>
        </pre>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Trash2, MoveUp, MoveDown, Type, AlignLeft, Box, Plus, Image as ImageIcon, Link as LinkIcon, Globe, LayoutTemplate, Columns, Rows, Navigation, Hash, ChevronDown, ChevronRight, X, ArrowRightLeft } from 'lucide-react';
import { Block, BlockType } from '../types';
import { WRAPPER_PALETTE } from '../constants';

interface BlockEditorProps {
  block: Block;
  index: number;
  totalBlocks: number;
  onUpdate: (id: string, updates: Partial<Block>) => void;
  onRemove: (id: string) => void;
  onMove: (id: string, direction: 'up' | 'down') => void;
  onAddChild: (parentId: string, type: BlockType) => void;
  wrapperDepth?: number;
}

export const BlockEditor: React.FC<BlockEditorProps> = ({
  block,
  index,
  totalBlocks,
  onUpdate,
  onRemove,
  onMove,
  onAddChild,
  wrapperDepth = 0,
}) => {
  const [isChangingType, setIsChangingType] = useState(false);

  const isWrapper = block.type === 'wrapper';
  const isNav = block.type === 'nav';
  const isContainer = isWrapper || isNav;
  const isImage = block.type === 'image';
  const isLink = block.type === 'link';
  const isHeading = block.type === 'heading';

  const isCollapsed = block.collapsed;
  const isNestedWrapper = isWrapper && wrapperDepth > 0;

  const getTypeIcon = (type: BlockType) => {
    switch (type) {
      case 'heading': return <Type size={14} />;
      case 'paragraph': return <AlignLeft size={14} />;
      case 'wrapper': return <Box size={14} />;
      case 'nav': return <Navigation size={14} />;
      case 'image': return <ImageIcon size={14} />;
      case 'link': return <LinkIcon size={14} />;
    }
  };

  const getSummary = () => {
    if (isContainer) {
      const count = block.children?.length || 0;
      return `${count} item${count !== 1 ? 's' : ''}`;
    }
    if (isHeading) {
      const level = block.headingLevel || 2;
      return `H${level}: ${block.content || 'Empty'}`;
    }
    if (isImage) return block.alt || block.url || 'Image block';
    if (isLink) return block.content || block.url || 'Link block';
    return block.content || `Empty ${block.type}`;
  };

  const allowedSwitchTypes: BlockType[] = ['heading', 'paragraph', 'link', 'image', 'wrapper', 'nav'];
  const allowedChildTypes: BlockType[] = ['heading', 'paragraph', 'image', 'link'];
  if (wrapperDepth < 1) {
    allowedChildTypes.push('wrapper');
  }

  const handleTypeChange = (newType: BlockType) => {
     onUpdate(block.id, { 
      type: newType, 
      children: (newType === 'wrapper' || newType === 'nav') ? block.children || [] : undefined,
      imageMode: newType === 'image' && !block.imageMode ? 'url' : block.imageMode,
      headingLevel: newType === 'heading' ? 2 : undefined
    });
    setIsChangingType(false);
  };

  return (
    <div className={`
      relative rounded-lg border shadow-sm transition-all group
      ${isContainer 
        ? isNav 
          ? 'bg-slate-50/50 dark:bg-slate-900/10 border-slate-200 dark:border-slate-800'
          : isNestedWrapper 
            ? 'bg-white dark:bg-slate-800 border-blue-300 dark:border-blue-700 shadow-md' 
            : 'bg-blue-50/50 dark:bg-blue-900/10 border-blue-200 dark:border-blue-800' 
        : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 hover:shadow-md'
      }
      ${isCollapsed ? 'p-2' : 'p-0 overflow-hidden'}
    `}>
      {/* --- HEADER --- */}
      <div className={`
        flex justify-between items-center 
        ${!isCollapsed ? 'px-4 py-3 bg-gray-50/50 dark:bg-slate-900/20 border-b border-gray-100 dark:border-slate-700/50' : ''}
      `}>
        <div className="flex items-center space-x-2 overflow-hidden flex-1">
          {/* Collapse Toggle */}
          <button
            onClick={() => onUpdate(block.id, { collapsed: !isCollapsed })}
            className="p-1 rounded hover:bg-gray-200 dark:hover:bg-slate-700 text-gray-400 hover:text-gray-600 dark:text-slate-500 dark:hover:text-slate-300 transition-colors"
          >
             {isCollapsed ? <ChevronRight size={16} /> : <ChevronDown size={16} />}
          </button>

          {/* Index Badge */}
          <span className={`text-[10px] font-mono px-1.5 py-0.5 rounded opacity-70 ${
            isContainer ? 'bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300' : 'bg-gray-200 text-gray-600 dark:bg-slate-700 dark:text-gray-400'
          }`}>
            #{index + 1}
          </span>

          {/* Type Switcher / Label */}
          {isChangingType && !isCollapsed ? (
            <div className="flex items-center bg-white dark:bg-slate-800 rounded border border-gray-200 dark:border-slate-600 p-0.5 shadow-sm animate-in fade-in zoom-in-95 duration-200">
               {allowedSwitchTypes.map((t) => {
                const isDisabled = t === 'wrapper' && wrapperDepth >= 2;
                if (isDisabled) return null;
                return (
                  <button
                    key={t}
                    onClick={() => handleTypeChange(t)}
                    className={`p-1.5 rounded hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors ${block.type === t ? 'text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/30' : 'text-gray-400 dark:text-slate-500'}`}
                    title={t.charAt(0).toUpperCase() + t.slice(1)}
                  >
                    {getTypeIcon(t)}
                  </button>
                );
              })}
              <div className="w-px h-4 bg-gray-200 dark:bg-slate-700 mx-1" />
              <button onClick={() => setIsChangingType(false)} className="p-1 hover:text-red-500 text-gray-400"><X size={12} /></button>
            </div>
          ) : (
            <button 
              onClick={() => !isCollapsed && setIsChangingType(true)}
              disabled={isCollapsed}
              className={`
                flex items-center space-x-1.5 px-2 py-1 rounded transition-all text-xs font-semibold tracking-wide uppercase
                ${isCollapsed 
                  ? 'cursor-default text-gray-500 dark:text-slate-400' 
                  : 'hover:bg-white dark:hover:bg-slate-800 hover:shadow-sm text-gray-700 dark:text-gray-300 border border-transparent hover:border-gray-200 dark:hover:border-slate-600'
                }
              `}
            >
              {getTypeIcon(block.type)}
              <span>{block.type}</span>
              {!isCollapsed && <ArrowRightLeft size={10} className="opacity-0 group-hover:opacity-40 ml-1" />}
            </button>
          )}

          {/* Collapsed Summary */}
          {isCollapsed && (
             <>
               <span className="text-gray-300 dark:text-gray-600">|</span>
               <span className="truncate text-xs text-gray-500 dark:text-slate-400 italic">{getSummary()}</span>
             </>
          )}
        </div>

        {/* Action Buttons */}
        <div className={`flex items-center space-x-0.5 flex-shrink-0 ${isChangingType ? 'opacity-30 pointer-events-none' : ''}`}>
          <button
            onClick={() => onMove(block.id, 'up')}
            disabled={index === 0}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-20 transition-colors"
          >
            <MoveUp size={14} />
          </button>
          <button
            onClick={() => onMove(block.id, 'down')}
            disabled={index === totalBlocks - 1}
            className="p-1.5 text-gray-400 hover:text-blue-600 disabled:opacity-20 transition-colors"
          >
            <MoveDown size={14} />
          </button>
          <div className="w-px h-3 bg-gray-200 dark:bg-slate-700 mx-1"></div>
          <button
            onClick={() => onRemove(block.id)}
            className="p-1.5 text-gray-400 hover:text-red-500 transition-colors"
          >
            <Trash2 size={14} />
          </button>
        </div>
      </div>

      {/* --- BODY --- */}
      {!isCollapsed && (
      <div className="p-4 space-y-4">

        {/* HEADING TOOLBAR */}
        {isHeading && (
          <div className="flex flex-wrap items-center justify-between gap-3 bg-gray-50 dark:bg-slate-900/50 p-2 rounded-md border border-gray-100 dark:border-slate-800">
             {/* Level Selector */}
            <div className="flex bg-white dark:bg-slate-800 p-0.5 rounded border border-gray-200 dark:border-slate-700 shadow-sm">
                {[2, 3, 4].map(level => (
                    <button
                        key={level}
                        onClick={() => onUpdate(block.id, { headingLevel: level as 2|3|4 })}
                        className={`px-3 py-1 text-xs font-bold rounded-sm transition-all ${
                            (block.headingLevel || 2) === level 
                            ? 'bg-gray-100 dark:bg-slate-600 text-black dark:text-white' 
                            : 'text-gray-400 hover:text-gray-600 dark:text-slate-500 dark:hover:text-slate-300'
                        }`}
                    >
                        H{level}
                    </button>
                ))}
            </div>

            {/* ID Input */}
            <div className="flex items-center space-x-2 flex-1 min-w-[120px]">
               <div className="text-gray-400"><Hash size={14} /></div>
               <input
                  type="text"
                  value={block.htmlId || ''}
                  onChange={(e) => onUpdate(block.id, { htmlId: e.target.value })}
                  placeholder="Anchor ID (optional)"
                  className="flex-1 bg-transparent border-b border-gray-200 dark:border-slate-700 focus:border-blue-400 outline-none text-xs font-mono py-1 text-gray-600 dark:text-gray-300 placeholder-gray-400"
                />
            </div>
          </div>
        )}

        {/* WRAPPER/NAV TOOLBAR */}
        {isWrapper && (
          <div className="flex flex-wrap items-center justify-between gap-3 bg-gray-50 dark:bg-slate-900/50 p-2 rounded-md border border-gray-100 dark:border-slate-800 mb-2">
            {/* Layout */}
             <div className="flex items-center space-x-1">
                <button
                  onClick={() => onUpdate(block.id, { layout: 'stack' })}
                  className={`p-1.5 rounded text-xs flex items-center gap-1 ${block.layout !== 'columns' ? 'bg-white dark:bg-slate-800 shadow-sm text-blue-600 dark:text-blue-400 font-medium' : 'text-gray-500 dark:text-slate-500'}`}
                >
                  <Rows size={14} /> <span>Stack</span>
                </button>
                <button
                  onClick={() => onUpdate(block.id, { layout: 'columns' })}
                  className={`p-1.5 rounded text-xs flex items-center gap-1 ${block.layout === 'columns' ? 'bg-white dark:bg-slate-800 shadow-sm text-blue-600 dark:text-blue-400 font-medium' : 'text-gray-500 dark:text-slate-500'}`}
                >
                  <Columns size={14} /> <span>Columns</span>
                </button>
             </div>

             {/* Color Palette */}
             <div className="flex items-center gap-1.5 bg-white dark:bg-slate-800 px-2 py-1 rounded-full border border-gray-100 dark:border-slate-700 shadow-sm">
                {WRAPPER_PALETTE.map(theme => (
                  <button 
                    key={theme.name}
                    onClick={() => onUpdate(block.id, { 
                      customStyles: { 
                        ...block.customStyles, 
                        backgroundColor: theme.bg, 
                        border: `1px solid ${theme.border}` 
                      } 
                    })}
                    className={`w-3.5 h-3.5 rounded-full transition-transform hover:scale-110 ${theme.dotClass} ${
                      block.customStyles?.backgroundColor === theme.bg ? 'ring-2 ring-offset-1 ring-blue-500 dark:ring-offset-slate-900 scale-110' : ''
                    }`}
                    title={theme.name}
                  />
                ))}
             </div>
          </div>
        )}

        {/* IMAGE EDITOR */}
        {isImage && (
          <div className="grid grid-cols-1 sm:grid-cols-[auto_1fr] gap-3 bg-gray-50 dark:bg-slate-900/50 p-3 rounded-md border border-gray-100 dark:border-slate-800">
             <div className="flex flex-col gap-2">
               <button
                  onClick={() => onUpdate(block.id, { imageMode: 'url' })}
                  className={`text-xs px-3 py-1.5 rounded border transition-all text-center ${block.imageMode === 'url' || !block.imageMode ? 'bg-white dark:bg-slate-800 border-blue-200 dark:border-blue-900 text-blue-600 dark:text-blue-400 font-medium shadow-sm' : 'border-transparent text-gray-500'}`}
               >
                 URL
               </button>
               <button
                  onClick={() => onUpdate(block.id, { imageMode: 'canvas' })}
                  className={`text-xs px-3 py-1.5 rounded border transition-all text-center ${block.imageMode === 'canvas' ? 'bg-white dark:bg-slate-800 border-blue-200 dark:border-blue-900 text-blue-600 dark:text-blue-400 font-medium shadow-sm' : 'border-transparent text-gray-500'}`}
               >
                 Canvas
               </button>
             </div>

             <div className="space-y-2">
                {block.imageMode === 'url' || !block.imageMode ? (
                  <input
                    type="text"
                    value={block.url || ''}
                    onChange={(e) => onUpdate(block.id, { url: e.target.value })}
                    placeholder="Image URL (https://...)"
                    className="w-full px-3 py-1.5 text-sm bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded focus:ring-1 focus:ring-blue-500 outline-none"
                  />
                ) : (
                  <div className="px-3 py-1.5 text-xs text-gray-400 italic bg-gray-100 dark:bg-slate-800/50 rounded border border-transparent">
                    Using placeholder canvas
                  </div>
                )}
                 <input
                  type="text"
                  value={block.alt || ''}
                  onChange={(e) => onUpdate(block.id, { alt: e.target.value })}
                  placeholder="Alt text description"
                  className="w-full px-3 py-1.5 text-sm bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded focus:ring-1 focus:ring-blue-500 outline-none"
                />
             </div>
          </div>
        )}

        {/* LINK EDITOR */}
        {isLink && (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
             <div className="space-y-1">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">Text</label>
                <input
                  type="text"
                  value={block.content}
                  onChange={(e) => onUpdate(block.id, { content: e.target.value })}
                  placeholder="Link Text"
                  className="w-full p-2 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded focus:ring-1 focus:ring-blue-500 outline-none text-sm"
                />
             </div>
             <div className="space-y-1">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">URL</label>
                <input
                  type="text"
                  value={block.url || ''}
                  onChange={(e) => onUpdate(block.id, { url: e.target.value })}
                  placeholder="https://... or #anchor"
                  className="w-full p-2 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded focus:ring-1 focus:ring-blue-500 outline-none text-sm font-mono"
                />
             </div>
          </div>
        )}

        {/* CONTAINER CHILDREN */}
        {isContainer && (
          <div className="space-y-3">
            <div className={`space-y-3 pl-3 ml-1 border-l-2 ${isNav ? 'border-slate-200 dark:border-slate-700' : 'border-blue-100 dark:border-blue-900'}`}>
              {block.children && block.children.length > 0 ? (
                block.children.map((childBlock, childIndex) => (
                  <BlockEditor
                    key={childBlock.id}
                    block={childBlock}
                    index={childIndex}
                    totalBlocks={block.children!.length}
                    onUpdate={onUpdate}
                    onRemove={onRemove}
                    onMove={onMove}
                    onAddChild={onAddChild}
                    wrapperDepth={isWrapper ? wrapperDepth + 1 : wrapperDepth}
                  />
                ))
              ) : (
                <div className="p-6 border-2 border-dashed border-gray-100 dark:border-slate-800 rounded-lg text-center">
                  <span className="text-xs text-gray-400 dark:text-slate-500 block mb-2">
                    {isNav ? 'Empty Navigation Bar' : 'Empty Wrapper'}
                  </span>
                </div>
              )}
            </div>

            <div className="flex flex-wrap gap-2 pl-4">
              {isNav ? (
                <button
                  onClick={() => onAddChild(block.id, 'link')}
                  className="flex items-center space-x-1.5 py-1.5 px-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 text-xs font-medium rounded hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shadow-sm"
                >
                  <Plus size={12} />
                  <span>Add Link</span>
                </button>
              ) : (
                allowedChildTypes.map(type => (
                   <button
                   key={type}
                   onClick={() => onAddChild(block.id, type)}
                   className="flex items-center space-x-1.5 py-1.5 px-3 bg-white dark:bg-slate-800 border border-blue-200 dark:border-blue-800/50 text-blue-600 dark:text-blue-400 text-xs font-medium rounded hover:bg-blue-50 dark:hover:bg-blue-900/20 transition-colors shadow-sm"
                 >
                   <Plus size={12} />
                   <span className="capitalize">{type}</span>
                 </button>
                ))
              )}
            </div>
          </div>
        )}

        {/* MAIN TEXT INPUT (Heading/Paragraph) */}
        {!isContainer && !isImage && !isLink && (
          <textarea
            value={block.content}
            onChange={(e) => onUpdate(block.id, { content: e.target.value })}
            placeholder={isHeading ? "Heading Text..." : "Paragraph Text..."}
            className={`
              w-full p-3 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-700 rounded-md 
              focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all resize-y text-sm text-gray-800 dark:text-gray-100
              ${isHeading ? 'font-bold min-h-[60px]' : 'min-h-[100px]'}
            `}
            style={isHeading ? { fontSize: '1.1rem' } : {}}
          />
        )}
      </div>
      )}
    </div>
  );
};
